      due_date: null,
      priority: 'medium',
      status: 'todo',
      location: userLocation,
      entity_type: 'none',
    },
  });

  // Fetch users for assignment
  const { data: users = [] } = useQuery({
    queryKey: ['users-for-tasks'],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('profiles')
        .select('id, full_name, avatar_url')
        .order('full_name');
      if (error) throw error;
      return data;
    },
  });

  // Reset form when task changes
  useEffect(() => {
    if (task) {
      form.reset({
        title: task.title,
        description: task.description || '',
        assigned_to: task.assigned_to || 'unassigned',
        due_date: task.due_date ? new Date(task.due_date) : null,
        priority: task.priority,
        status: task.status,
        location: task.location || userLocation,
        entity_type: task.entity_type || 'none',
      });
    } else {
      form.reset({
        title: '',
        description: '',
        assigned_to: 'unassigned',
        due_date: null,
        priority: 'medium',
        status: 'todo',
        location: userLocation,
        entity_type: 'none',
      });
    }
  }, [task, form, userLocation]);

  // Create/Update mutation
  const mutation = useMutation({
    mutationFn: async (data: FormData) => {
      const assignedTo = data.assigned_to && data.assigned_to !== 'unassigned' ? data.assigned_to : null;
      const entityType = data.entity_type && data.entity_type !== 'none' ? data.entity_type : null;

      const isNewAssignment = !task && assignedTo;
      const isReassignment = task && assignedTo && assignedTo !== task.assigned_to;

      if (task) {
        const { error } = await supabase
          .from('tasks')
          .update({
            title: data.title,
            description: data.description || null,
            assigned_to: assignedTo,
            due_date: data.due_date?.toISOString() || null,
            priority: data.priority,
            status: data.status,
            location: data.location || null,
            entity_type: entityType,
          })
          .eq('id', task.id);
        if (error) throw error;
      } else {
        const { error } = await supabase
          .from('tasks')
          .insert({
            title: data.title,
            description: data.description || null,
            assigned_to: assignedTo,
            due_date: data.due_date?.toISOString() || null,
            priority: data.priority,
            status: data.status,
            location: data.location || null,
            entity_type: entityType,
            created_by: user?.id!,
          });
        if (error) throw error;
      }

      if ((isNewAssignment || isReassignment) && assignedTo) {
        const assignerProfile = await supabase
          .from('profiles')
          .select('full_name')
          .eq('id', user?.id!)
          .single();

        const assignerName = assignerProfile.data?.full_name || 'Foydalanuvchi';
        const formattedDueDate = data.due_date ? format(data.due_date, 'dd.MM.yyyy') : undefined;

        notifyTaskAssigned(
          assignedTo,
          data.title,
          assignerName,
          data.priority,
          data.location,
          formattedDueDate
        );
      }
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['tasks'] });
      toast.success(task ? t('task_updated') : t('task_created'));
      onOpenChange(false);
    },
    onError: (error) => {
      console.error('Task error:', error);
      toast.error(task ? t('error_updating_task') : t('error_creating_task'));
    },
  });

  const onSubmit = (data: FormData) => {
    mutation.mutate(data);
  };

  const getInitials = (name: string | null) => {
    if (!name) return '?';
    return name.split(' ').map(n => n[0]).join('').toUpperCase().slice(0, 2);
  };

  return (
    <ResponsiveDialog open={open} onOpenChange={onOpenChange}>
      <ResponsiveDialogContent fullScreen={isMobile} scrollable>
        <ResponsiveDialogHeader>
          <ResponsiveDialogTitle>
            {task ? t('edit_task') : t('new_task')}
          </ResponsiveDialogTitle>
        </ResponsiveDialogHeader>

        <ResponsiveDialogBody>
          <Form {...form}>
            <form id="task-form" onSubmit={form.handleSubmit(onSubmit)} className="space-y-4">
              {/* Title */}
              <FormField
                control={form.control}
                name="title"
                rules={{ required: t('title_required') }}
                render={({ field }) => (
                  <FormItem>
                    <FormLabel>{t('title')}</FormLabel>
                    <FormControl>
                      <Input 
                        placeholder={t('task_title_placeholder')} 
                        {...field} 
                        mobileOptimized
                      />
                    </FormControl>
                    <FormMessage />
                  </FormItem>
                )}
              />

              {/* Description */}
              <FormField
                control={form.control}
                name="description"
                render={({ field }) => (
                  <FormItem>
                    <FormLabel>{t('description')}</FormLabel>
                    <FormControl>
                      <Textarea
                        placeholder={t('task_description_placeholder')}
                        className="min-h-[100px] md:min-h-[80px]"
                        {...field}
                      />
                    </FormControl>
                    <FormMessage />
                  </FormItem>
                )}
              />

              {/* Quick Priority Selector for Mobile */}
              {isMobile && (
                <FormField
                  control={form.control}
                  name="priority"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel>{t('priority')}</FormLabel>
                      <div className="grid grid-cols-4 gap-2">
                        {priorityOptions.map((option) => {
                          const Icon = option.icon;
                          const isSelected = field.value === option.value;
                          return (
                            <button
                              key={option.value}
                              type="button"
                              onClick={() => field.onChange(option.value)}
                              className={cn(
                                "flex flex-col items-center gap-1 p-3 rounded-lg border-2 transition-all active:scale-95",
                                isSelected 
                                  ? "border-primary bg-primary/10" 
                                  : "border-muted hover:border-muted-foreground/30"
                              )}
                            >
                              {Icon ? (
                                <Icon className={cn("h-5 w-5", option.color)} />
                              ) : (
                                <div className={cn("h-5 w-5 rounded-full", 
                                  option.value === 'low' ? 'bg-slate-400' : 'bg-blue-500'
                                )} />
                              )}
                              <span className="text-xs font-medium">{t(option.label)}</span>
                            </button>
                          );
                        })}
                      </div>
                      <FormMessage />
                    </FormItem>
                  )}
                />
              )}

              {/* Quick Status Selector for Mobile */}
              {isMobile && (
                <FormField
                  control={form.control}
                  name="status"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel>{t('status')}</FormLabel>
                      <div className="flex flex-wrap gap-2">
                        {statusOptions.map((option) => {
                          const Icon = option.icon;
                          const isSelected = field.value === option.value;
                          return (
                            <button
                              key={option.value}
                              type="button"
                              onClick={() => field.onChange(option.value)}
                              className={cn(
                                "flex items-center gap-1.5 px-3 py-2 rounded-full border-2 transition-all active:scale-95",
                                isSelected 
                                  ? "border-primary bg-primary/10" 
                                  : "border-muted hover:border-muted-foreground/30"
                              )}
                            >
                              <Icon className={cn("h-4 w-4", option.color)} />
                              <span className="text-xs font-medium">{t(option.label)}</span>
                            </button>
                          );
                        })}
                      </div>
                      <FormMessage />
                    </FormItem>
                  )}
                />
              )}

              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                {/* Assigned To */}
                <FormField
                  control={form.control}
                  name="assigned_to"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel>{t('assigned_to')}</FormLabel>
                      <Select onValueChange={field.onChange} value={field.value}>
                        <FormControl>
                          <SelectTrigger className={cn(isMobile && "h-12")}>
                            <SelectValue placeholder={t('select_user')} />
                          </SelectTrigger>
                        </FormControl>
                        <SelectContent>
                          <SelectItem value="unassigned">{t('unassigned')}</SelectItem>
                          {users.map((u) => (
                            <SelectItem key={u.id} value={u.id}>
                              <div className="flex items-center gap-2">
                                <Avatar className="h-6 w-6">
                                  <AvatarImage src={u.avatar_url || undefined} />
                                  <AvatarFallback className="text-xs">
                                    {getInitials(u.full_name)}
                                  </AvatarFallback>
                                </Avatar>
                                <span>{u.full_name || u.id}</span>
                              </div>
                            </SelectItem>
                          ))}
                        </SelectContent>
                      </Select>
                      <FormMessage />
                    </FormItem>
                  )}
                />

                {/* Due Date */}
                <FormField
                  control={form.control}
                  name="due_date"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel>{t('due_date')}</FormLabel>
                      <Popover>
                        <PopoverTrigger asChild>
                          <FormControl>
                            <Button
                              variant="outline"
                              className={cn(
                                "w-full pl-3 text-left font-normal",
                                isMobile && "h-12",
                                !field.value && "text-muted-foreground"
                              )}
                            >
                              {field.value ? format(field.value, 'PPP') : t('select_date')}
                              <CalendarIcon className="ml-auto h-4 w-4 opacity-50" />
                            </Button>
                          </FormControl>
                        </PopoverTrigger>
                        <PopoverContent className="w-auto p-0" align="start">
                          <Calendar
                            mode="single"
                            selected={field.value || undefined}
                            onSelect={field.onChange}
                            initialFocus
                          />
                        </PopoverContent>
                      </Popover>
                      <FormMessage />
                    </FormItem>
                  )}
                />

                {/* Priority - Desktop only */}
                {!isMobile && (
                  <FormField
                    control={form.control}
                    name="priority"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel>{t('priority')}</FormLabel>
                        <Select onValueChange={field.onChange} value={field.value}>
                          <FormControl>
                            <SelectTrigger>
                              <SelectValue />
                            </SelectTrigger>
                          </FormControl>
                          <SelectContent>
                            {priorityOptions.map((option) => (
                              <SelectItem key={option.value} value={option.value}>
                                <div className="flex items-center gap-2">
                                  {option.icon && <option.icon className={cn("h-4 w-4", option.color)} />}
                                  {t(option.label)}
                                </div>
                              </SelectItem>
                            ))}
                          </SelectContent>
                        </Select>
                        <FormMessage />
                      </FormItem>
                    )}
                  />
                )}

                {/* Status - Desktop only */}
                {!isMobile && (
                  <FormField
                    control={form.control}
                    name="status"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel>{t('status')}</FormLabel>
                        <Select onValueChange={field.onChange} value={field.value}>
                          <FormControl>
                            <SelectTrigger>
                              <SelectValue />
                            </SelectTrigger>
                          </FormControl>
                          <SelectContent>
                            {statusOptions.map((option) => (
                              <SelectItem key={option.value} value={option.value}>
                                <div className="flex items-center gap-2">
                                  <option.icon className={cn("h-4 w-4", option.color)} />
                                  {t(option.label)}
                                </div>
                              </SelectItem>
                            ))}
                          </SelectContent>
                        </Select>
                        <FormMessage />
                      </FormItem>
                    )}
                  />
                )}

                {/* Location */}
                <FormField
                  control={form.control}
                  name="location"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel>{t('location')}</FormLabel>
                      <Select onValueChange={field.onChange} value={field.value}>
                        <FormControl>
                          <SelectTrigger className={cn(isMobile && "h-12")}>
                            <SelectValue />
                          </SelectTrigger>
                        </FormControl>
                        <SelectContent>
                          <SelectItem value="china">{t('china')}</SelectItem>
                          <SelectItem value="uzbekistan">{t('uzbekistan')}</SelectItem>
                        </SelectContent>
                      </Select>
                      <FormMessage />
                    </FormItem>
                  )}
                />

                {/* Entity Type */}
                <FormField
                  control={form.control}
                  name="entity_type"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel>{t('related_to')}</FormLabel>
                      <Select onValueChange={field.onChange} value={field.value}>
                        <FormControl>
                          <SelectTrigger className={cn(isMobile && "h-12")}>
                            <SelectValue placeholder={t('none')} />
                          </SelectTrigger>
                        </FormControl>
                        <SelectContent>
                          <SelectItem value="none">{t('none')}</SelectItem>
                          <SelectItem value="product">{t('products')}</SelectItem>
                          <SelectItem value="box">{t('boxes')}</SelectItem>
                          <SelectItem value="shipment">{t('shipments')}</SelectItem>
                          <SelectItem value="claim">{t('claims')}</SelectItem>
                        </SelectContent>
                      </Select>
                      <FormMessage />
                    </FormItem>
                  )}
                />
              </div>
            </form>
          </Form>

          {/* Comments section for existing tasks */}
          {task && (
            <div className="mt-6 pt-6 border-t">
              <TaskComments taskId={task.id} />
            </div>
          )}
        </ResponsiveDialogBody>

        <ResponsiveDialogFooter>
          <Button type="button" variant="outline" onClick={() => onOpenChange(false)}>
            {t('cancel')}
          </Button>
          <Button type="submit" form="task-form" disabled={mutation.isPending}>
            {mutation.isPending && <Loader2 className="h-4 w-4 mr-2 animate-spin" />}
            {task ? t('save_changes') : t('create_task')}
          </Button>
        </ResponsiveDialogFooter>
      </ResponsiveDialogContent>
    </ResponsiveDialog>
  );
}

import { useState } from 'react';
import { useTranslation } from 'react-i18next';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/contexts/AuthContext';
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
} from '@/components/ui/dialog';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Textarea } from '@/components/ui/textarea';
import { Label } from '@/components/ui/label';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { toast } from 'sonner';
import { Plus, FileText, Trash2, Play, Loader2 } from 'lucide-react';
import { ScrollArea } from '@/components/ui/scroll-area';

interface TaskTemplate {
  id: string;
  name: string;
  description: string | null;
  title_template: string;
  description_template: string | null;
  default_priority: string | null;
  default_location: string | null;
  default_entity_type: string | null;
  estimated_duration_hours: number | null;
  is_active: boolean;
  created_at: string;
}

interface TaskTemplatesDialogProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  onUseTemplate: (template: TaskTemplate) => void;
}

export function TaskTemplatesDialog({ open, onOpenChange, onUseTemplate }: TaskTemplatesDialogProps) {
  const { t } = useTranslation();
  const { user } = useAuth();
  const queryClient = useQueryClient();
  const [isCreating, setIsCreating] = useState(false);
  const [newTemplate, setNewTemplate] = useState({
    name: '',
    description: '',
    title_template: '',
    description_template: '',
    default_priority: 'medium',
    default_location: '',
    estimated_duration_hours: 0,
  });

  const { data: templates = [], isLoading } = useQuery({
    queryKey: ['task-templates'],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('task_templates')
        .select('*')
        .eq('is_active', true)
        .order('name');
      if (error) throw error;
      return data as TaskTemplate[];
    },
  });

  const createMutation = useMutation({
    mutationFn: async () => {
      const { error } = await supabase.from('task_templates').insert({
        name: newTemplate.name,
        description: newTemplate.description || null,
        title_template: newTemplate.title_template,
        description_template: newTemplate.description_template || null,
        default_priority: newTemplate.default_priority,
        default_location: newTemplate.default_location || null,
        estimated_duration_hours: newTemplate.estimated_duration_hours || null,
        created_by: user?.id!,
      });
      if (error) throw error;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['task-templates'] });
      toast.success(t('template_created'));
      setIsCreating(false);
      setNewTemplate({
        name: '',
        description: '',
        title_template: '',
        description_template: '',
        default_priority: 'medium',
        default_location: '',
        estimated_duration_hours: 0,
      });
    },
    onError: () => {
      toast.error(t('error_creating_template'));
    },
  });

  const deleteMutation = useMutation({
    mutationFn: async (id: string) => {
      const { error } = await supabase
        .from('task_templates')
        .update({ is_active: false })
        .eq('id', id);
      if (error) throw error;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['task-templates'] });
      toast.success(t('template_deleted'));
    },
  });

  const priorityColors: Record<string, string> = {
    low: 'bg-gray-100 text-gray-700 dark:bg-gray-800 dark:text-gray-300',
    medium: 'bg-blue-100 text-blue-700 dark:bg-blue-900 dark:text-blue-300',
    high: 'bg-orange-100 text-orange-700 dark:bg-orange-900 dark:text-orange-300',
    urgent: 'bg-red-100 text-red-700 dark:bg-red-900 dark:text-red-300',
  };

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="max-w-3xl max-h-[95dvh] sm:max-h-[85vh] overflow-hidden flex flex-col">
        <DialogHeader>
          <DialogTitle className="flex items-center gap-2">
            <FileText className="h-5 w-5" />
            {t('task_templates')}
          </DialogTitle>
        </DialogHeader>

        <div className="flex justify-end">
          <Button
            size="sm"
            variant={isCreating ? 'secondary' : 'default'}
            onClick={() => setIsCreating(!isCreating)}
          >
            <Plus className="h-4 w-4 mr-1" />
            {isCreating ? t('cancel') : t('new_template')}
          </Button>
        </div>

        {isCreating && (
          <Card className="border-primary/50">
            <CardHeader className="pb-3">
              <CardTitle className="text-base">{t('create_template')}</CardTitle>
            </CardHeader>
            <CardContent className="space-y-3">
              <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                <div className="space-y-1.5">
                  <Label className="text-xs">{t('template_name')}</Label>
                  <Input
                    value={newTemplate.name}
                    onChange={(e) => setNewTemplate({ ...newTemplate, name: e.target.value })}
                    placeholder={t('template_name_placeholder')}
                  />
                </div>
                <div className="space-y-1.5">
                  <Label className="text-xs">{t('default_priority')}</Label>
                  <Select
                    value={newTemplate.default_priority}
                    onValueChange={(v) => setNewTemplate({ ...newTemplate, default_priority: v })}
                  >
                    <SelectTrigger>
                      <SelectValue />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="low">{t('low')}</SelectItem>
                      <SelectItem value="medium">{t('medium')}</SelectItem>
                      <SelectItem value="high">{t('high')}</SelectItem>
                      <SelectItem value="urgent">{t('urgent')}</SelectItem>
                    </SelectContent>
                  </Select>
                </div>
              </div>
              <div className="space-y-1.5">
                <Label className="text-xs">{t('task_title_template')}</Label>
                <Input
                  value={newTemplate.title_template}
                  onChange={(e) => setNewTemplate({ ...newTemplate, title_template: e.target.value })}
                  placeholder={t('task_title_template_placeholder')}
                />
              </div>
              <div className="space-y-1.5">
                <Label className="text-xs">{t('description')}</Label>
                <Textarea
                  value={newTemplate.description_template}
                  onChange={(e) => setNewTemplate({ ...newTemplate, description_template: e.target.value })}
                  rows={2}
                  placeholder={t('task_description_placeholder')}
                />
              </div>
              <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                <div className="space-y-1.5">
                  <Label className="text-xs">{t('default_location')}</Label>
                  <Select
                    value={newTemplate.default_location}
                    onValueChange={(v) => setNewTemplate({ ...newTemplate, default_location: v })}
                  >
                    <SelectTrigger>
                      <SelectValue placeholder={t('select_location')} />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="china">{t('china')}</SelectItem>
                      <SelectItem value="uzbekistan">{t('uzbekistan')}</SelectItem>
                    </SelectContent>
                  </Select>
                </div>
                <div className="space-y-1.5">
                  <Label className="text-xs">{t('estimated_hours')}</Label>
                  <Input
                    type="number"
                    min={0}
                    value={newTemplate.estimated_duration_hours}
                    onChange={(e) => setNewTemplate({ ...newTemplate, estimated_duration_hours: parseInt(e.target.value) || 0 })}
                  />
                </div>
              </div>
              <div className="flex justify-end">
                <Button
                  size="sm"
                  onClick={() => createMutation.mutate()}
                  disabled={!newTemplate.name || !newTemplate.title_template || createMutation.isPending}
                >
                  {createMutation.isPending && <Loader2 className="h-4 w-4 mr-1 animate-spin" />}
                  {t('create_template')}
                </Button>
              </div>
            </CardContent>
          </Card>
        )}

        <ScrollArea className="h-[400px] pr-4">
          {isLoading ? (
            <div className="flex items-center justify-center h-32">
              <Loader2 className="h-6 w-6 animate-spin text-muted-foreground" />
            </div>
          ) : templates.length === 0 ? (
            <div className="text-center py-8 text-muted-foreground">
              <FileText className="h-10 w-10 mx-auto mb-2 opacity-50" />
              <p>{t('no_templates')}</p>
            </div>
          ) : (
            <div className="space-y-2">
              {templates.map((template) => (
                <Card key={template.id} className="hover:bg-muted/50 transition-colors">
                  <CardContent className="p-4">
                    <div className="flex items-start justify-between gap-4">
                      <div className="flex-1 min-w-0">
                        <div className="flex items-center gap-2 mb-1">
                          <h4 className="font-medium text-sm">{template.name}</h4>
                          {template.default_priority && (
                            <Badge variant="secondary" className={`text-xs ${priorityColors[template.default_priority]}`}>
                              {t(template.default_priority)}
                            </Badge>
                          )}
                          {template.default_location && (
                            <Badge variant="outline" className="text-xs">
                              {t(template.default_location)}
                            </Badge>
                          )}
                        </div>
                        <p className="text-sm text-muted-foreground truncate">
                          {template.title_template}
                        </p>
                        {template.description && (
                          <p className="text-xs text-muted-foreground mt-1">{template.description}</p>
                        )}
                      </div>
                      <div className="flex items-center gap-1">
                        <Button
                          size="sm"
                          variant="default"
                          onClick={(e) => {
                            e.preventDefault();
                            e.stopPropagation();
                            try {
                              // Close dialog first to prevent state conflicts
                              onOpenChange(false);
                              // Use setTimeout to ensure dialog closes before template is applied
                              setTimeout(() => {
                                onUseTemplate(template);
                              }, 100);
                            } catch (error) {
                              console.error('Error using template:', error);
                              toast.error(t('error_using_template') || 'Shablon ishlatishda xatolik');
                            }
                          }}
                        >
                          <Play className="h-3 w-3 mr-1" />
                          {t('use')}
                        </Button>
                        <Button
                          size="sm"
                          variant="ghost"
                          onClick={() => deleteMutation.mutate(template.id)}
                        >
                          <Trash2 className="h-4 w-4 text-destructive" />
                        </Button>
                      </div>
                    </div>
                  </CardContent>
                </Card>
              ))}
            </div>
          )}
        </ScrollArea>
      </DialogContent>
    </Dialog>
  );
}

import * as React from "react";
import { type DialogProps } from "@radix-ui/react-dialog";
import { Command as CommandPrimitive } from "cmdk";
import { Search } from "lucide-react";

import { cn } from "@/lib/utils";
import { Dialog, DialogContent } from "@/components/ui/dialog";

const Command = React.forwardRef<
  React.ElementRef<typeof CommandPrimitive>,
  React.ComponentPropsWithoutRef<typeof CommandPrimitive>
>(({ className, ...props }, ref) => (
  <CommandPrimitive
    ref={ref}
    className={cn(
      "flex h-full w-full flex-col overflow-hidden rounded-md bg-popover text-popover-foreground",
      className,
    )}
    {...props}
  />
));
Command.displayName = CommandPrimitive.displayName;

interface CommandDialogProps extends DialogProps {}

const CommandDialog = ({ children, ...props }: CommandDialogProps) => {
  return (
