import { useState, useCallback, useRef } from 'react';
import { supabase } from '@/integrations/supabase/client';

interface StreamState {
  isStreaming: boolean;
  streamedContent: string;
  error: string | null;
  conversationId: string | null;
}

interface StreamOptions {
  onStart?: () => void;
  onChunk?: (chunk: string) => void;
  onComplete?: (fullResponse: string, conversationId: string) => void;
  onError?: (error: string) => void;
}

export function useAliAIStream() {
  const [state, setState] = useState<StreamState>({
    isStreaming: false,
    streamedContent: '',
    error: null,
    conversationId: null,
  });

  const abortControllerRef = useRef<AbortController | null>(null);

  const streamMessage = useCallback(async (
    message: string,
    existingConversationId: string | null,
    options?: StreamOptions
  ) => {
    // Abort any existing stream
    if (abortControllerRef.current) {
      abortControllerRef.current.abort();
    }

    abortControllerRef.current = new AbortController();

    setState({
      isStreaming: true,
      streamedContent: '',
      error: null,
      conversationId: existingConversationId,
    });

    options?.onStart?.();

    try {
      const { data: sessionData } = await supabase.auth.getSession();
      const token = sessionData.session?.access_token;

      if (!token) {
        throw new Error('Not authenticated');
      }

      const response = await fetch(
        `${import.meta.env.VITE_SUPABASE_URL}/functions/v1/ali-ai-brain`,
        {
          method: 'POST',
          headers: {
            'Content-Type': 'application/json',
            'Authorization': `Bearer ${token}`,
          },
          body: JSON.stringify({
            message,
            conversationId: existingConversationId,
            stream: true,
          }),
          signal: abortControllerRef.current.signal,
        }
      );

      if (!response.ok) {
        const errorData = await response.json();
        throw new Error(errorData.error || 'Failed to send message');
      }

      // Get conversation ID from header
      const newConversationId = response.headers.get('X-Conversation-Id') || existingConversationId;

      if (!response.body) {
        throw new Error('No response body');
      }

      const reader = response.body.getReader();
      const decoder = new TextDecoder();
      let textBuffer = '';
      let fullResponse = '';
      let isFirstChunk = true;

      // Helper function to clean and sanitize content - minimal approach
      const sanitizeContent = (content: string): string => {
        if (!content) return '';

        // Remove BOM (byte order mark)
        let cleaned = content.replace(/^\uFEFF/, '');

        // Remove control characters (except tab, newline, carriage return)
        cleaned = cleaned.replace(/[\x00-\x08\x0B\x0C\x0E-\x1F\x7F]/g, '');

        // For first chunk, trim leading whitespace/newlines only
        if (isFirstChunk && cleaned.length > 0) {
          cleaned = cleaned.replace(/^[\s\n\r]+/, '');
          if (cleaned.length > 0) {
            isFirstChunk = false;
          }
        }

        return cleaned;
      };

      while (true) {
        const { done, value } = await reader.read();
        if (done) break;

        textBuffer += decoder.decode(value, { stream: true });

        // Process complete lines only
        const lines = textBuffer.split('\n');
        // Keep the last potentially incomplete line in the buffer
        textBuffer = lines.pop() || '';

        for (let line of lines) {
          line = line.trim();

          // Skip empty lines, comments, and non-data lines
          if (!line || line.startsWith(':') || !line.startsWith('data: ')) continue;

          const jsonStr = line.slice(6).trim();
          if (jsonStr === '[DONE]') continue;

          try {
            const parsed = JSON.parse(jsonStr);
            const content = parsed.choices?.[0]?.delta?.content as string | undefined;
            if (content) {
              const sanitized = sanitizeContent(content);
              if (sanitized) {
                fullResponse += sanitized;
                options?.onChunk?.(sanitized);
                setState(prev => ({
                  ...prev,
                  streamedContent: fullResponse,
                  conversationId: newConversationId,
                }));
              }
            }
          } catch {
            // Incomplete JSON - this line might be split across chunks
            // Don't put it back, just skip it - next chunk will have the data
          }
        }
      }

      // Final flush - process any remaining complete data in buffer
      if (textBuffer.trim()) {
        const finalLines = textBuffer.split('\n');
        for (let raw of finalLines) {
          raw = raw.trim();
          if (!raw || raw.startsWith(':') || !raw.startsWith('data: ')) continue;
          const jsonStr = raw.slice(6).trim();
          if (jsonStr === '[DONE]') continue;
          try {
            const parsed = JSON.parse(jsonStr);
            const content = parsed.choices?.[0]?.delta?.content as string | undefined;
            if (content) {
              const sanitized = sanitizeContent(content);
              if (sanitized) {
                fullResponse += sanitized;
              }
            }
          } catch { /* ignore incomplete final chunk */ }
        }
      }

      // Final cleanup of the complete response
      fullResponse = fullResponse.trim();

      setState(prev => ({
        ...prev,
        isStreaming: false,
        streamedContent: fullResponse,
        conversationId: newConversationId,
      }));

      options?.onComplete?.(fullResponse, newConversationId || '');

    } catch (error) {
      if ((error as Error).name === 'AbortError') {
        console.log('Stream aborted');
        return;
      }

      const errorMessage = error instanceof Error ? error.message : 'Unknown error';
      setState(prev => ({
        ...prev,
        isStreaming: false,
        error: errorMessage,
      }));
      options?.onError?.(errorMessage);
    }
  }, []);

  const cancelStream = useCallback(() => {
    if (abortControllerRef.current) {
      abortControllerRef.current.abort();
      abortControllerRef.current = null;
    }
    setState(prev => ({
      ...prev,
      isStreaming: false,
    }));
  }, []);

  const reset = useCallback(() => {
    cancelStream();
    setState({
      isStreaming: false,
      streamedContent: '',
      error: null,
      conversationId: null,
    });
  }, [cancelStream]);

  return {
    ...state,
    streamMessage,
    cancelStream,
    reset,
  };
}

import { useState, useCallback, useEffect, useRef } from 'react';
import { Capacitor } from '@capacitor/core';

interface SyncTask {
  id: string;
  type: string;
  data: any;
  createdAt: Date;
  retryCount: number;
  maxRetries: number;
}

interface SyncResult {
  success: boolean;
  syncedCount: number;
  failedCount: number;
  errors: string[];
}

const SYNC_STORAGE_KEY = 'pending-sync-tasks';
const MAX_RETRIES = 3;

export function useBackgroundSync() {
  const [isNative] = useState(Capacitor.isNativePlatform());
  const [pendingTasks, setPendingTasks] = useState<SyncTask[]>([]);
  const [isSyncing, setIsSyncing] = useState(false);
  const [lastSyncAt, setLastSyncAt] = useState<Date | null>(null);
  const syncInProgress = useRef(false);

  // Load pending tasks from storage
  useEffect(() => {
    try {
      const stored = localStorage.getItem(SYNC_STORAGE_KEY);
      if (stored) {
        const tasks = JSON.parse(stored);
        setPendingTasks(tasks.map((t: any) => ({
          ...t,
          createdAt: new Date(t.createdAt),
        })));
      }
    } catch (error) {
      console.error('Failed to load pending sync tasks:', error);
    }
  }, []);

  // Save pending tasks to storage
  const savePendingTasks = useCallback((tasks: SyncTask[]) => {
    try {
      localStorage.setItem(SYNC_STORAGE_KEY, JSON.stringify(tasks));
      setPendingTasks(tasks);
    } catch (error) {
      console.error('Failed to save pending sync tasks:', error);
    }
  }, []);

  // Add a task to sync queue
  const queueSync = useCallback((type: string, data: any): string => {
    const task: SyncTask = {
      id: `sync-${Date.now()}-${Math.random().toString(36).slice(2)}`,
      type,
      data,
      createdAt: new Date(),
      retryCount: 0,
      maxRetries: MAX_RETRIES,
    };

    savePendingTasks([...pendingTasks, task]);
    return task.id;
  }, [pendingTasks, savePendingTasks]);

  // Process a single sync task
  const processSyncTask = useCallback(async (task: SyncTask): Promise<boolean> => {
    try {
      switch (task.type) {
        case 'box_verification':
          // Sync box verification data
          // await supabase.from('boxes').update(task.data).eq('id', task.data.id);
          console.log('Syncing box verification:', task.data);
          break;

        case 'task_status':
          // Sync task status change
          // await supabase.from('tasks').update(task.data).eq('id', task.data.id);
          console.log('Syncing task status:', task.data);
          break;

        case 'product_update':
          // Sync product update
          // await supabase.from('products').update(task.data).eq('id', task.data.id);
          console.log('Syncing product update:', task.data);
          break;

        case 'defect_claim':
          // Sync defect claim
          // await supabase.from('defect_claims').insert(task.data);
          console.log('Syncing defect claim:', task.data);
          break;

        default:
          console.warn('Unknown sync task type:', task.type);
          return false;
      }

      return true;
    } catch (error) {
      console.error('Sync task failed:', task.id, error);
      return false;
    }
  }, []);

  // Run sync for all pending tasks
  const sync = useCallback(async (): Promise<SyncResult> => {
    if (syncInProgress.current || pendingTasks.length === 0) {
      return { success: true, syncedCount: 0, failedCount: 0, errors: [] };
    }

    syncInProgress.current = true;
    setIsSyncing(true);

    const results: SyncResult = {
      success: true,
      syncedCount: 0,
      failedCount: 0,
      errors: [],
    };

    const remainingTasks: SyncTask[] = [];

    for (const task of pendingTasks) {
      const success = await processSyncTask(task);

      if (success) {
        results.syncedCount++;
      } else {
        results.failedCount++;

        if (task.retryCount < task.maxRetries) {
          remainingTasks.push({
            ...task,
            retryCount: task.retryCount + 1,
          });
        } else {
          results.errors.push(`Task ${task.id} failed after ${task.maxRetries} retries`);
        }
      }
    }

    savePendingTasks(remainingTasks);
    setLastSyncAt(new Date());
    setIsSyncing(false);
    syncInProgress.current = false;

    results.success = results.failedCount === 0;
    return results;
  }, [pendingTasks, processSyncTask, savePendingTasks]);

  // Auto-sync when coming online
  useEffect(() => {
    const handleOnline = () => {
      console.log('Back online, triggering sync...');
      sync();
    };

    window.addEventListener('online', handleOnline);
    return () => window.removeEventListener('online', handleOnline);
  }, [sync]);

  // Register background sync (for PWA)
  useEffect(() => {
    if ('serviceWorker' in navigator && 'sync' in (window as any).ServiceWorkerRegistration?.prototype) {
      navigator.serviceWorker.ready.then(registration => {
        // Register periodic background sync
        if ('periodicSync' in registration) {
          (registration as any).periodicSync.register('sync-data', {
            minInterval: 5 * 60 * 1000, // 5 minutes
          }).catch((e: Error) => console.log('Periodic sync registration failed:', e));
        }
      });
    }
  }, []);

  // Clear all pending tasks
  const clearPending = useCallback(() => {
    savePendingTasks([]);
  }, [savePendingTasks]);

  // Get count of pending tasks
  const getPendingCount = useCallback(() => pendingTasks.length, [pendingTasks]);

  return {
    pendingTasks,
    isSyncing,
    lastSyncAt,
    queueSync,
    sync,
    clearPending,
    getPendingCount,
  };
}

import { useQuery, useQueries } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';

export interface FBOInvoice {
  id: string;
  invoiceNumber: string;
  status: string;
  createdAt: string;
  acceptedAt?: string;
  productCount: number;
  totalQuantity: number;
  storeName?: string;
}

export interface FBOReturn {
  returnId: string;
  productId: string;
  productTitle: string;
  skuTitle: string;
  quantity: number;
  returnReason: string;
  status: string;
  createdAt: string;
  storeName?: string;
}

export interface FBOOrder {
  orderId: string;
  orderItemId: string;
  productId: string;
  productTitle: string;
  skuTitle: string;
  amount: number;
  sellerPrice: number;
  commission: number;
  sellerProfit: number;
  deliveryFee: number;
  status: string;
  dateIssued: string;
  storeName?: string;
}

export interface FBOSummary {
  invoices: FBOInvoice[];
  returns: FBOReturn[];
  orders: FBOOrder[];
  totals: {
    totalInvoices: number;
    totalReturns: number;
    totalReturnQuantity: number;
    defectedCount: number;
    lastDeliveryDate?: string;
    storeCount?: number;
    storeNames?: string[];
    totalOrders: number;
    totalOrderItems: number;
    totalRevenue: number;
    totalCommission: number;
    totalProfit: number;
  };
  isLoading: boolean;
  error: Error | null;
  refetch: () => void;
  isAggregated?: boolean;
}

interface UzumStore {
  id: string;
  name: string;
}

async function fetchFBOForStore(storeId: string, storeName?: string) {
  const { data, error } = await supabase.functions.invoke('uzum-finance', {
    body: { 
      store_id: storeId, 
      action: 'fbo_summary' 
    }
  });

  if (error) throw error;

  const result = data?.result || data;

  const invoices: FBOInvoice[] = (result?.invoices || []).map((inv: any) => ({
    id: inv.id?.toString() || '',
    invoiceNumber: inv.invoiceNumber || inv.externalNumber || `INV-${inv.id}`,
    status: inv.status || '',
    createdAt: inv.dateCreated ? new Date(inv.dateCreated).toISOString() : '',
    acceptedAt: inv.acceptedAt || inv.completedDate ? new Date(inv.completedDate).toISOString() : undefined,
    productCount: inv.productCount || 0,
    totalQuantity: inv.totalQuantity || 0,
    storeName,
  }));

  const returns: FBOReturn[] = (result?.returns || []).map((ret: any) => ({
    returnId: ret.id?.toString() || '',
    productId: ret.productId?.toString() || '',
    productTitle: ret.stock?.title || 'FBO Qaytarish',
    skuTitle: ret.type || '',
    quantity: 1,
    returnReason: ret.type || '',
    status: ret.status || '',
    createdAt: ret.dateCreated ? new Date(ret.dateCreated).toISOString() : '',
    storeName,
  }));

  const orders: FBOOrder[] = (result?.orders || []).map((ord: any) => ({
    orderId: ord.orderId?.toString() || '',
    orderItemId: ord.orderItemId?.toString() || '',
    productId: ord.productId?.toString() || '',
    productTitle: ord.productTitle || ord.skuTitle || '',
    skuTitle: ord.skuTitle || '',
    amount: ord.amount || 1,
    sellerPrice: ord.sellPrice || ord.sellerPrice || 0,
    commission: ord.commission || 0,
    sellerProfit: ord.sellerProfit || 0,
    deliveryFee: ord.logisticDeliveryFee || 0,
    status: ord.status || '',
    dateIssued: ord.date ? new Date(ord.date).toISOString() : (ord.dateIssued ? new Date(ord.dateIssued).toISOString() : ''),
    storeName,
  }));

  const ordersTotals = result?.orders_totals || { revenue: 0, commission: 0, profit: 0, deliveryFees: 0, itemCount: 0 };

  return { invoices, returns, orders, ordersTotals, storeName };
}

function buildSummary(
  invoices: FBOInvoice[],
  returns: FBOReturn[],
  orders: FBOOrder[],
  ordersTotals: any,
  isLoading: boolean,
  error: Error | null,
  refetch: () => void,
  isAggregated: boolean,
  storeNames?: string[],
): FBOSummary {
  const defectedCount = returns.filter(r => r.status === 'DEFECTED').length;
  const totalReturnQuantity = returns.reduce((sum, r) => sum + r.quantity, 0);

  const deliveredInvoices = invoices.filter(inv => inv.acceptedAt);
  const lastDeliveryDate = deliveredInvoices.length > 0
    ? deliveredInvoices.sort((a, b) =>
        new Date(b.acceptedAt!).getTime() - new Date(a.acceptedAt!).getTime()
      )[0].acceptedAt
    : undefined;

  return {
    invoices,
    returns,
    orders,
    totals: {
      totalInvoices: invoices.length,
      totalReturns: returns.length,
      totalReturnQuantity,
      defectedCount,
      lastDeliveryDate,
      storeCount: storeNames?.length,
      storeNames,
      totalOrders: orders.length,
      totalOrderItems: ordersTotals.itemCount || 0,
      totalRevenue: ordersTotals.revenue || 0,
      totalCommission: ordersTotals.commission || 0,
      totalProfit: ordersTotals.profit || 0,
    },
    isLoading,
    error,
    refetch,
    isAggregated,
  };
}

export function useFBOData(storeId: string | null, uzumStores?: UzumStore[]): FBOSummary {
  // Single store query
  const singleStoreQuery = useQuery({
    queryKey: ['fbo-summary', storeId],
    queryFn: () => fetchFBOForStore(storeId!),
    enabled: !!storeId,
    staleTime: 1000 * 60 * 5,
    gcTime: 1000 * 60 * 30,
  });

  // Aggregated queries for all Uzum stores
  const aggregatedQueries = useQueries({
    queries: (!storeId && uzumStores?.length) 
      ? uzumStores.map(store => ({
          queryKey: ['fbo-summary', store.id],
          queryFn: () => fetchFBOForStore(store.id, store.name),
          staleTime: 1000 * 60 * 5,
          gcTime: 1000 * 60 * 30,
        }))
      : [],
  });

  // Handle single store case
  if (storeId) {
    const result = singleStoreQuery.data;
    const invoices = result?.invoices || [];
    const returns = result?.returns || [];
    const orders = result?.orders || [];
    const ordersTotals = result?.ordersTotals || { revenue: 0, commission: 0, profit: 0, deliveryFees: 0, itemCount: 0 };

    return buildSummary(
      invoices, returns, orders, ordersTotals,
      singleStoreQuery.isLoading,
      singleStoreQuery.error as Error | null,
      () => { singleStoreQuery.refetch(); },
      false,
    );
  }

  // Handle aggregated case
  const isLoading = aggregatedQueries.some(q => q.isLoading);
  const error = aggregatedQueries.find(q => q.error)?.error as Error | null;

  const allInvoices: FBOInvoice[] = [];
  const allReturns: FBOReturn[] = [];
  const allOrders: FBOOrder[] = [];
  const storeNames: string[] = [];
  let aggregatedOrdersTotals = { revenue: 0, commission: 0, profit: 0, deliveryFees: 0, itemCount: 0 };

  aggregatedQueries.forEach(query => {
    if (query.data) {
      allInvoices.push(...query.data.invoices);
      allReturns.push(...query.data.returns);
      allOrders.push(...(query.data.orders || []));

      const ot = query.data.ordersTotals || { revenue: 0, commission: 0, profit: 0, deliveryFees: 0, itemCount: 0 };
      aggregatedOrdersTotals.revenue += ot.revenue;
      aggregatedOrdersTotals.commission += ot.commission;
      aggregatedOrdersTotals.profit += ot.profit;
      aggregatedOrdersTotals.deliveryFees += ot.deliveryFees;
      aggregatedOrdersTotals.itemCount += ot.itemCount;

      if (query.data.storeName && (query.data.invoices.length > 0 || query.data.returns.length > 0 || (query.data.orders?.length || 0) > 0)) {
        if (!storeNames.includes(query.data.storeName)) {
          storeNames.push(query.data.storeName);
        }
      }
    }
  });

  return buildSummary(
    allInvoices, allReturns, allOrders, aggregatedOrdersTotals,
    isLoading,
    error,
    () => { aggregatedQueries.forEach(q => q.refetch()); },
    true,
    storeNames,
  );
}

