              <div className="w-10 h-10 sm:w-12 sm:h-12 rounded-xl bg-cyan-500/10 flex items-center justify-center">
                <ClipboardCheck className="h-5 w-5 sm:h-6 sm:w-6 text-cyan-500" />
              </div>
              <div>
                <p className="text-xs sm:text-sm text-muted-foreground">{t('cn_verified')}</p>
                <p className="text-xl sm:text-2xl font-bold text-cyan-500">{stats?.arrivedPendingCount || 0}</p>
              </div>
            </div>
          </Card>
        </Link>

        <Card className="p-4 sm:p-6 bg-card border-border hover:shadow-lg transition-all">
          <div className="flex items-center gap-3 sm:gap-4">
            <div className="w-10 h-10 sm:w-12 sm:h-12 rounded-xl bg-emerald-500/10 flex items-center justify-center">
              <Package className="h-5 w-5 sm:h-6 sm:w-6 text-emerald-500" />
            </div>
            <div>
              <p className="text-xs sm:text-sm text-muted-foreground">{t('cn_ok_products')}</p>
              <p className="text-xl sm:text-2xl font-bold text-emerald-500">{stats?.totalOkItemsToday || 0}</p>
            </div>
          </div>
        </Card>
      </div>

      {/* Main Content Grid */}
      <div className="grid grid-cols-1 gap-6">
        {/* Pending Verification Queue */}
        <Card className="p-4 sm:p-6 bg-card border-border">
          <div className="flex items-center justify-between mb-4">
            <h2 className="text-base sm:text-lg font-semibold text-foreground flex items-center gap-2">
              <ClipboardCheck className="h-5 w-5 text-yellow-500" />
              {t('cn_pending_boxes')}
            </h2>
            <Badge variant="secondary" className="bg-yellow-500/10 text-yellow-500">
              {stats?.pendingVerificationBoxes?.length || 0} ta
            </Badge>
          </div>

          {stats?.pendingVerificationBoxes && stats.pendingVerificationBoxes.length > 0 ? <div className="space-y-3">
              {stats.pendingVerificationBoxes.map((box: any) => <div key={box.id} className="flex items-center justify-between p-3 bg-muted/50 rounded-lg border border-border hover:bg-muted transition-colors">
                  <div className="flex items-center gap-3">
                    <div className="w-10 h-10 rounded-lg bg-yellow-500/10 flex items-center justify-center">
                      <Box className="h-5 w-5 text-yellow-500" />
                    </div>
                    <div>
                      <p className="font-medium text-foreground">{box.box_number}</p>
                      <p className="text-xs text-muted-foreground">
                        {t('cn_products_count', { count: box.product_items?.length || 0 })}
                      </p>
                    </div>
                  </div>
                  <Link to={`/crm/boxes?box=${box.id}`}>
                    <Button size="sm" variant="outline" className="gap-1">
                      {t('cn_inspect')}
                      <ArrowRight className="h-4 w-4" />
                    </Button>
                  </Link>
                </div>)}
            </div> : <div className="flex flex-col items-center justify-center py-8 text-muted-foreground">
              <CheckCircle2 className="h-12 w-12 mb-3 text-green-500/50" />
              <p className="text-sm">{t('cn_no_pending')}</p>
            </div>}
        </Card>

        {/* In Transit Boxes - Tracking shipped boxes */}
        <Card className="p-4 sm:p-6 bg-card border-border">
          <div className="flex items-center justify-between mb-4">
            <h2 className="text-base sm:text-lg font-semibold text-foreground flex items-center gap-2">
              <Truck className="h-5 w-5 text-indigo-500" />
              {t('cn_in_transit')}
            </h2>
            <Badge variant="secondary" className="bg-indigo-500/10 text-indigo-500">
              {stats?.inTransitCount || 0} ta
            </Badge>
          </div>

          {stats?.inTransitBoxes && stats.inTransitBoxes.length > 0 ? <div className="space-y-3">
              {stats.inTransitBoxes.map((box: any) => {
            const daysInTransit = box.updated_at ? Math.floor((new Date().getTime() - new Date(box.updated_at).getTime()) / (1000 * 60 * 60 * 24)) : 0;
            return <div key={box.id} className="flex items-center justify-between p-3 bg-muted/50 rounded-lg border border-indigo-500/20 hover:bg-muted transition-colors">
                    <div className="flex items-center gap-3">
                      <div className="w-10 h-10 rounded-lg bg-indigo-500/10 flex items-center justify-center">
                        <Truck className="h-5 w-5 text-indigo-500" />
                      </div>
                      <div>
                        <p className="font-medium text-foreground">{box.box_number}</p>
                        <div className="flex items-center gap-2 text-xs text-muted-foreground">
                          <span>{t('cn_products_count', { count: box.product_items?.length || 0 })}</span>
                          <span>•</span>
                          <span className="text-indigo-500">{t('cn_days_in_transit', { days: daysInTransit })}</span>
                        </div>
                      </div>
                    </div>
                    <div className="text-right">
                      {box.estimated_arrival ? <div className="flex items-center gap-1 text-xs text-muted-foreground">
                          <Calendar className="h-3 w-3" />
                          <span>{new Date(box.estimated_arrival).toLocaleDateString('uz-UZ')}</span>
                        </div> : <span className="text-xs text-muted-foreground">{t('cn_eta_unknown')}</span>}
                    </div>
                  </div>;
          })}

              {(stats?.inTransitCount || 0) > 10 && <Link to="/crm/shipments">
                  <Button variant="ghost" className="w-full gap-2 mt-2">
                    {t('cn_view_all', { count: stats.inTransitAllCount })}
                    <ArrowRight className="h-4 w-4" />
                  </Button>
                </Link>}
            </div> : <div className="flex flex-col items-center justify-center py-8 text-muted-foreground">
              <Truck className="h-12 w-12 mb-3 opacity-50" />
               <p className="text-sm">{t('cn_no_in_transit')}</p>
               <p className="text-xs">{t('cn_send_hint')}</p>
            </div>}
        </Card>
      </div>

      {/* Recent Verification Activity */}
      {stats?.recentVerifications && stats.recentVerifications.length > 0 && <Card className="p-4 sm:p-6 bg-card border-border">
           <h2 className="text-base sm:text-lg font-semibold text-foreground flex items-center gap-2 mb-4">
            <Clock className="h-5 w-5 text-primary" />
            {t('cn_recent_verifications')}
           </h2>

          <div className="space-y-2">
            {stats.recentVerifications.map((v: any) => <div key={v.id} className="flex items-center justify-between p-3 bg-muted/50 rounded-lg">
                <div className="flex items-center gap-3">
                  <div className={`w-8 h-8 rounded-lg flex items-center justify-center ${v.status === 'completed' ? 'bg-green-500/10' : 'bg-yellow-500/10'}`}>
                    {v.status === 'completed' ? <CheckCircle2 className="h-4 w-4 text-green-500" /> : <Clock className="h-4 w-4 text-yellow-500" />}
                  </div>
                  <div>
                    <p className="font-medium text-foreground text-sm">
                      {v.boxes?.box_number || 'Quti'}
                    </p>
                    <p className="text-xs text-muted-foreground">
                      {v.status === 'completed' ? t('cn_completed') : t('cn_in_progress')}
                    </p>
                  </div>
                </div>
                <div className="flex items-center gap-2 text-xs">
                  {v.status === 'completed' && <>
                      <span className="text-green-500">{v.ok_count || 0} OK</span>
                      {(v.defective_count || 0) > 0 && <span className="text-red-500">{v.defective_count} {t('cn_defect_label')}</span>}
                      {(v.missing_count || 0) > 0 && <span className="text-yellow-500">{v.missing_count} {t('cn_missing_label')}</span>}
                    </>}
                </div>
              </div>)}
          </div>
        </Card>}
    </div>
  );

  // Wrap with PullToRefresh on mobile
  if (isMobile) {
    return (
      <PullToRefresh onRefresh={handleRefresh} className="min-h-full">
        {content}
      </PullToRefresh>
    );
  }

  return content;
}

import { useState } from 'react';
import { useIsMobile } from '@/hooks/use-mobile';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';
import { fetchAllRows } from '@/lib/fetchAllRows';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Badge } from '@/components/ui/badge';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from '@/components/ui/table';
import { 
  Warehouse, 
  MapPin, 
  Package, 
  AlertTriangle, 
  TrendingDown, 
  ArrowRightLeft,
  Plus,
  Search,
  Building2,
  CheckCircle
} from 'lucide-react';
import { useTranslation } from 'react-i18next';
import { toast } from 'sonner';
import { format } from 'date-fns';
import { WarehouseDialog } from '@/components/inventory/WarehouseDialog';
import { LocationDialog } from '@/components/inventory/LocationDialog';
import { StockAlertPanel } from '@/components/inventory/StockAlertPanel';
import { TashkentWarehouseIndicators } from '@/components/inventory/TashkentWarehouseIndicators';
import { Link } from 'react-router-dom';

export default function Inventory() {
  const isMobile = useIsMobile();
  const { t } = useTranslation();
  const queryClient = useQueryClient();

  const [searchQuery, setSearchQuery] = useState('');
  const [selectedWarehouse, setSelectedWarehouse] = useState<string>('all');
  const [isWarehouseDialogOpen, setIsWarehouseDialogOpen] = useState(false);
  const [isLocationDialogOpen, setIsLocationDialogOpen] = useState(false);
  const [selectedWarehouseForLocation, setSelectedWarehouseForLocation] = useState<any>(null);

  // Fetch warehouses
  const { data: warehouses = [] } = useQuery({
    queryKey: ['warehouses'],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('warehouses')
        .select('*')
        .order('location', { ascending: true });
      if (error) throw error;
      return data;
    },
  });

  // Fetch warehouse locations
  const { data: locations = [] } = useQuery({
    queryKey: ['warehouse-locations', selectedWarehouse],
    queryFn: async () => {
      let query = supabase
        .from('warehouse_locations')
        .select('*, warehouse:warehouses(name, location)')
        .order('zone', { ascending: true });

      if (selectedWarehouse !== 'all') {
        query = query.eq('warehouse_id', selectedWarehouse);
      }

      const { data, error } = await query;
      if (error) throw error;
      return data;
    },
  });

  // Fetch stock alerts
  const { data: alerts = [] } = useQuery({
    queryKey: ['stock-alerts'],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('stock_alerts')
        .select(`
          *,
          product:products(name),
          warehouse:warehouses(name)
        `)
        .eq('is_resolved', false)
        .order('created_at', { ascending: false });
      if (error) throw error;
      return data;
    },
  });

  // Fetch inventory movements
  const { data: movements = [] } = useQuery({
    queryKey: ['inventory-movements'],
    queryFn: async () => {
      return await fetchAllRows(
        supabase
          .from('inventory_movements')
          .select(`
            *,
            product:products(name),
            from_location:warehouse_locations!inventory_movements_from_location_id_fkey(zone, shelf),
            to_location:warehouse_locations!inventory_movements_to_location_id_fkey(zone, shelf)
          `)
          .order('created_at', { ascending: false })
      );
    },
  });

  // Fetch product items with locations
  const { data: productItems = [] } = useQuery({
    queryKey: ['product-items-inventory', selectedWarehouse],
    queryFn: async () => {
      let query = supabase
        .from('product_items')
        .select(`
          *,
          product:products(name, category),
          location:warehouse_locations(zone, shelf, warehouse:warehouses(name, location))
        `)
        .not('warehouse_location_id', 'is', null)
        .order('created_at', { ascending: false });

      const { data, error } = await query;
      if (error) throw error;
      return data;
    },
  });

  // Stats
  const stats = {
    totalWarehouses: warehouses.length,
    chinaWarehouses: warehouses.filter(w => w.location === 'china').length,
    uzWarehouses: warehouses.filter(w => w.location === 'uzbekistan').length,
    totalLocations: locations.length,
    activeAlerts: alerts.length,
    totalItems: productItems.length,
  };

  // Filter locations by search
  const filteredLocations = locations.filter(loc => {
    if (!searchQuery) return true;
    const search = searchQuery.toLowerCase();
    return (
      loc.zone?.toLowerCase().includes(search) ||
      loc.shelf?.toLowerCase().includes(search) ||
      loc.warehouse?.name?.toLowerCase().includes(search)
    );
  });

  const handleAddLocation = (warehouse: any) => {
    if (!warehouse || !warehouse.id || !warehouse.name) {
      toast.error(t('inv_data_incomplete'));
      return;
    }
    setSelectedWarehouseForLocation(warehouse);
    setIsLocationDialogOpen(true);
  };

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div>
          <h1 className="text-2xl font-bold text-foreground">{t('inventory.title')}</h1>
          <p className="text-muted-foreground">{t('inventory.description')}</p>
        </div>
        <Button onClick={() => setIsWarehouseDialogOpen(true)}>
          <Plus className="h-4 w-4 mr-2" />
          {t('inventory.newWarehouse')}
        </Button>
      </div>

      {/* Stats Cards */}
      <div className="grid grid-cols-2 md:grid-cols-4 lg:grid-cols-6 gap-4">
        <Card 
          className="bg-gradient-to-br from-primary/10 to-primary/5 cursor-pointer hover:shadow-lg transition-all"
          onClick={() => document.querySelector('[value="warehouses"]')?.dispatchEvent(new MouseEvent('click', { bubbles: true }))}
        >
          <CardContent className="p-4">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-sm text-muted-foreground">{t('inventory.warehouses')}</p>
                <p className="text-2xl font-bold">{stats.totalWarehouses}</p>
              </div>
              <Building2 className="h-8 w-8 text-primary/50" />
            </div>
          </CardContent>
        </Card>
        <Card 
          className="bg-gradient-to-br from-red-500/10 to-red-500/5 cursor-pointer hover:shadow-lg transition-all"
          onClick={() => setSelectedWarehouse(warehouses.find(w => w.location === 'china')?.id || 'all')}
        >
          <CardContent className="p-4">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-sm text-muted-foreground">{t('china')}</p>
                <p className="text-2xl font-bold text-red-600">{stats.chinaWarehouses}</p>
              </div>
              <Warehouse className="h-8 w-8 text-red-500/50" />
            </div>
          </CardContent>
        </Card>
        <Card 
          className="bg-gradient-to-br from-blue-500/10 to-blue-500/5 cursor-pointer hover:shadow-lg transition-all"
          onClick={() => setSelectedWarehouse(warehouses.find(w => w.location === 'uzbekistan')?.id || 'all')}
        >
          <CardContent className="p-4">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-sm text-muted-foreground">{t('uzbekistan')}</p>
                <p className="text-2xl font-bold text-blue-600">{stats.uzWarehouses}</p>
              </div>
              <Warehouse className="h-8 w-8 text-blue-500/50" />
            </div>
          </CardContent>
        </Card>
        <Card 
          className="bg-gradient-to-br from-green-500/10 to-green-500/5 cursor-pointer hover:shadow-lg transition-all"
          onClick={() => document.querySelector('[value="locations"]')?.dispatchEvent(new MouseEvent('click', { bubbles: true }))}
        >
          <CardContent className="p-4">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-sm text-muted-foreground">{t('inventory.locations')}</p>
                <p className="text-2xl font-bold text-green-600">{stats.totalLocations}</p>
              </div>
              <MapPin className="h-8 w-8 text-green-500/50" />
            </div>
          </CardContent>
        </Card>
        <Card 
          className="bg-gradient-to-br from-orange-500/10 to-orange-500/5 cursor-pointer hover:shadow-lg transition-all"
          onClick={() => document.querySelector('[value="alerts"]')?.dispatchEvent(new MouseEvent('click', { bubbles: true }))}
        >
          <CardContent className="p-4">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-sm text-muted-foreground">{t('inventory.alerts')}</p>
                <p className="text-2xl font-bold text-orange-600">{stats.activeAlerts}</p>
              </div>
              <AlertTriangle className="h-8 w-8 text-orange-500/50" />
            </div>
          </CardContent>
        </Card>
        <Link to="/crm/products">
          <Card className="bg-gradient-to-br from-purple-500/10 to-purple-500/5 cursor-pointer hover:shadow-lg transition-all h-full">
            <CardContent className="p-4">
              <div className="flex items-center justify-between">
                <div>
                  <p className="text-sm text-muted-foreground">{t('products')}</p>
                  <p className="text-2xl font-bold text-purple-600">{stats.totalItems}</p>
                </div>
                <Package className="h-8 w-8 text-purple-500/50" />
              </div>
            </CardContent>
          </Card>
        </Link>
      </div>

      {/* Tabs */}
      <Tabs defaultValue="indicators" className="space-y-4">
        <TabsList className="flex-wrap">
          <TabsTrigger value="indicators">{t('inventory.keyIndicators')}</TabsTrigger>
          <TabsTrigger value="warehouses">{t('inventory.warehouses')}</TabsTrigger>
          <TabsTrigger value="locations">{t('inventory.locations')}</TabsTrigger>
          <TabsTrigger value="alerts">
            {t('inventory.alerts')}
            {alerts.length > 0 && (
              <Badge variant="destructive" className="ml-2">{alerts.length}</Badge>
            )}
          </TabsTrigger>
          <TabsTrigger value="movements">{t('inventory.movements')}</TabsTrigger>
        </TabsList>

        {/* Key Indicators Tab */}
        <TabsContent value="indicators">
          <TashkentWarehouseIndicators />
        </TabsContent>

        {/* Warehouses Tab */}
        <TabsContent value="warehouses" className="space-y-4">
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
            {warehouses.map((warehouse) => {
              const warehouseLocations = locations.filter(l => l.warehouse_id === warehouse.id);
              const totalCapacity = warehouseLocations.reduce((sum, l) => sum + (l.capacity || 0), 0);
              const totalUsed = warehouseLocations.reduce((sum, l) => sum + (l.current_count || 0), 0);
              const usagePercent = totalCapacity > 0 ? (totalUsed / totalCapacity) * 100 : 0;

              return (
                <Card key={warehouse.id} className="hover:shadow-lg transition-shadow">
                  <CardHeader className="pb-2">
                    <div className="flex items-center justify-between">
                      <CardTitle className="text-lg flex items-center gap-2">
                        <Warehouse className="h-5 w-5" />
                        {warehouse.name}
                      </CardTitle>
                      <Badge variant={warehouse.location === 'china' ? 'destructive' : 'default'}>
                        {warehouse.location === 'china' ? t('china') : t('uzbekistan')}
                      </Badge>
                    </div>
                  </CardHeader>
                  <CardContent className="space-y-4">
                    {warehouse.address && (
                      <p className="text-sm text-muted-foreground flex items-center gap-1">
                        <MapPin className="h-4 w-4" />
                        {warehouse.address}
                      </p>
                    )}

                    <div className="space-y-2">
                      <div className="flex justify-between text-sm">
                        <span>{t('inv_locations_count')}: {warehouseLocations.length}</span>
                        <span>{usagePercent.toFixed(0)}% {t('inv_occupied_pct')}</span>
                      </div>
                      <div className="w-full h-2 bg-muted rounded-full overflow-hidden">
                        <div 
                          className={`h-full transition-all ${
                            usagePercent > 80 ? 'bg-red-500' : 
                            usagePercent > 50 ? 'bg-yellow-500' : 'bg-green-500'
                          }`}
                          style={{ width: `${usagePercent}%` }}
                        />
                      </div>
                    </div>

                    <Button 
                      variant="outline" 
                      size="sm" 
                      className="w-full"
                      onClick={() => handleAddLocation(warehouse)}
                    >
                      <Plus className="h-4 w-4 mr-2" />
                      {t('inventory.addLocation')}
                    </Button>
                  </CardContent>
                </Card>
              );
            })}
          </div>
        </TabsContent>

        {/* Locations Tab */}
        <TabsContent value="locations" className="space-y-4">
          <Card>
            <CardContent className="p-4">
              <div className="flex flex-col sm:flex-row gap-4">
                <div className="relative flex-1">
                  <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
                  <Input
                    placeholder={t('inv_search_zone_shelf')}
                    value={searchQuery}
                    onChange={(e) => setSearchQuery(e.target.value)}
                    className="pl-10"
                  />
                </div>
              </div>
            </CardContent>
          </Card>

          <Card>
            <CardContent className={isMobile ? "p-2" : "p-0"}>
              {filteredLocations.length === 0 ? (
                <div className="text-center py-8 text-muted-foreground">{t('inventory.noLocations')}</div>
              ) : isMobile ? (
                <div className="space-y-2">
                  {filteredLocations.map((location) => {
                    const usage = location.capacity > 0 ? (location.current_count / location.capacity) * 100 : 0;
                    return (
                      <div key={location.id} className="border rounded-lg p-3 space-y-2">
                        <div className="flex items-center justify-between">
                          <Badge variant="outline">{location.warehouse?.name}</Badge>
                          <Badge variant="outline" className={
                            usage > 80 ? 'bg-red-500/20 text-red-600' :
                            usage > 50 ? 'bg-yellow-500/20 text-yellow-600' :
                            'bg-green-500/20 text-green-600'
                          }>{usage.toFixed(0)}%</Badge>
                        </div>
                        <div className="flex items-center gap-4 text-sm">
                          <span><span className="text-muted-foreground">{t('inv_zone_label')}:</span> <span className="font-medium">{location.zone}</span></span>
                          <span><span className="text-muted-foreground">{t('inv_shelf_label')}:</span> {location.shelf || '-'}</span>
                        </div>
                        <div className="flex items-center justify-between text-xs text-muted-foreground">
                          <span>{t('inv_capacity_label')}: {location.capacity}</span>
                          <span>{t('inv_current_label')}: {location.current_count}</span>
                        </div>
                        <div className="w-full h-1.5 bg-muted rounded-full overflow-hidden">
                          <div className={`h-full ${usage > 80 ? 'bg-red-500' : usage > 50 ? 'bg-yellow-500' : 'bg-green-500'}`} style={{ width: `${Math.min(usage, 100)}%` }} />
                        </div>
                      </div>
                    );
                  })}
                </div>
              ) : (
                <Table>
                  <TableHeader>
                    <TableRow>
                      <TableHead>{t('inv_warehouse_label')}</TableHead>
                      <TableHead>{t('inv_zone_label')}</TableHead>
                      <TableHead>{t('inv_shelf_label')}</TableHead>
                      <TableHead>{t('inv_position_label')}</TableHead>
                      <TableHead>{t('inv_capacity_label')}</TableHead>
                      <TableHead>{t('inv_current_label')}</TableHead>
                      <TableHead>{t('inv_status_label')}</TableHead>
                    </TableRow>
                  </TableHeader>
                  <TableBody>
                    {filteredLocations.map((location) => {
                      const usage = location.capacity > 0 ? (location.current_count / location.capacity) * 100 : 0;
                      return (
                        <TableRow key={location.id}>
                          <TableCell><Badge variant="outline">{location.warehouse?.name}</Badge></TableCell>
                          <TableCell className="font-medium">{location.zone}</TableCell>
                          <TableCell>{location.shelf || '-'}</TableCell>
                          <TableCell>{location.position || '-'}</TableCell>
                          <TableCell>{location.capacity}</TableCell>
                          <TableCell>{location.current_count}</TableCell>
                          <TableCell>
                            <Badge variant="outline" className={
                              usage > 80 ? 'bg-red-500/20 text-red-600' :
                              usage > 50 ? 'bg-yellow-500/20 text-yellow-600' :
                              'bg-green-500/20 text-green-600'
                            }>{usage.toFixed(0)}%</Badge>
                          </TableCell>
                        </TableRow>
                      );
                    })}
                  </TableBody>
                </Table>
              )}
            </CardContent>
          </Card>
        </TabsContent>

        {/* Alerts Tab */}
        <TabsContent value="alerts">
          <StockAlertPanel alerts={alerts} />
        </TabsContent>

        {/* Movements Tab */}
        <TabsContent value="movements" className="space-y-4">
          <Card>
            <CardContent className={isMobile ? "p-2" : "p-0"}>
              {movements.length === 0 ? (
                <div className="text-center py-8 text-muted-foreground">{t('inventory.noMovements')}</div>
              ) : isMobile ? (
                <div className="space-y-2">
                  {movements.map((movement) => (
                    <div key={movement.id} className="border rounded-lg p-3 space-y-1.5">
                      <div className="flex items-center justify-between">
                        <span className="font-medium text-sm truncate flex-1">{movement.product?.name || '-'}</span>
                        <Badge variant="outline" className="capitalize ml-2">{movement.movement_type}</Badge>
                      </div>
                      <div className="flex items-center gap-2 text-xs text-muted-foreground">
                        <span>{movement.from_location ? `${movement.from_location.zone}/${movement.from_location.shelf || '-'}` : '-'}</span>
                        <ArrowRightLeft className="h-3 w-3" />
                        <span>{movement.to_location ? `${movement.to_location.zone}/${movement.to_location.shelf || '-'}` : '-'}</span>
                      </div>
                      <div className="flex items-center justify-between text-xs">
                        <span className="text-muted-foreground">{format(new Date(movement.created_at), 'dd.MM.yyyy HH:mm')}</span>
                        <Badge variant="secondary">{movement.quantity} {t('pcs')}</Badge>
                      </div>
                    </div>
                  ))}
                </div>
              ) : (
                <Table>
                  <TableHeader>
                    <TableRow>
                      <TableHead>{t('inv_date_label')}</TableHead>
                      <TableHead>{t('inv_product_label')}</TableHead>
                      <TableHead>{t('inv_movement_type_label')}</TableHead>
                      <TableHead>{t('inv_from_label')}</TableHead>
                      <TableHead>{t('inv_to_label')}</TableHead>
                      <TableHead>{t('inv_qty_label')}</TableHead>
                    </TableRow>
                  </TableHeader>
                  <TableBody>
                    {movements.map((movement) => (
                      <TableRow key={movement.id}>
                        <TableCell>{format(new Date(movement.created_at), 'dd.MM.yyyy HH:mm')}</TableCell>
                        <TableCell>{movement.product?.name || '-'}</TableCell>
                        <TableCell><Badge variant="outline" className="capitalize">{movement.movement_type}</Badge></TableCell>
                        <TableCell>{movement.from_location ? `${movement.from_location.zone}/${movement.from_location.shelf || '-'}` : '-'}</TableCell>
                        <TableCell>{movement.to_location ? `${movement.to_location.zone}/${movement.to_location.shelf || '-'}` : '-'}</TableCell>
                        <TableCell>{movement.quantity}</TableCell>
                      </TableRow>
                    ))}
                  </TableBody>
                </Table>
              )}
            </CardContent>
          </Card>
        </TabsContent>
      </Tabs>

      {/* Dialogs */}
      <WarehouseDialog
        open={isWarehouseDialogOpen}
        onOpenChange={setIsWarehouseDialogOpen}
      />

      <LocationDialog
        open={isLocationDialogOpen}
        onOpenChange={setIsLocationDialogOpen}
        warehouse={selectedWarehouseForLocation}
      />
    </div>
  );
}

import { useState, useMemo } from "react";
import { useNavigate } from "react-router-dom";
import { useIsMobile } from "@/hooks/use-mobile";
import { useQuery } from "@tanstack/react-query";
import { useTranslation } from "react-i18next";
import { supabase } from "@/integrations/supabase/client";
import { fetchAllRows } from '@/lib/fetchAllRows';
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Tabs, TabsList, TabsTrigger, TabsContent } from "@/components/ui/tabs";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Skeleton } from "@/components/ui/skeleton";

import {
  TrendingUp,
  TrendingDown,
  DollarSign,
  Package,
  BarChart3,
  Brain,
  RefreshCw,
  ShoppingCart,
  AlertTriangle,
  Target,
  LineChart,
  PieChart,
  Percent,
  Receipt,
  Store,
} from "lucide-react";
import {
  AreaChart,
  Area,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  ResponsiveContainer,
  BarChart,
  Bar,
  PieChart as RechartsPieChart,
  Pie,
  Cell,
} from "recharts";
import { format, subDays } from "date-fns";
import { toast } from "sonner";

const COLORS = [
  'hsl(var(--chart-1))',
  'hsl(var(--chart-2))',
  'hsl(var(--chart-3))',
  'hsl(var(--chart-4))',
  'hsl(var(--chart-5))',
  '#8b5cf6',
  '#ec4899',
  '#14b8a6',
  '#f97316',
  '#06b6d4',
  '#84cc16',
  '#a855f7',
];

const UZUM_COLORS = ['#a855f7', '#8b5cf6', '#7c3aed', '#6d28d9', '#c084fc', '#d8b4fe', '#9333ea', '#581c87'];
const YANDEX_COLORS = ['#f59e0b', '#d97706', '#b45309', '#fbbf24'];

type PlatformTab = 'all' | 'uzum' | 'yandex';

export default function MarketplaceAnalytics() {
  const { t } = useTranslation();
  const navigate = useNavigate();
  const isMobile = useIsMobile();
  const [activeTab, setActiveTab] = useState("sales");
  const [platformTab, setPlatformTab] = useState<PlatformTab>('all');
  const [selectedStoreId, setSelectedStoreId] = useState<string | null>(null);
  const [isRefreshing, setIsRefreshing] = useState(false);

  // Fetch stores
  const { data: stores } = useQuery({
    queryKey: ['marketplace-stores-analytics'],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('marketplace_stores')
        .select('id, name, platform')
        .eq('is_active', true);
      if (error) throw error;
      return data;
    },
  });

  // PRIMARY data source: marketplace_finance_summary (accurate financial KPIs)
  const { data: financeSummary, isLoading: financeLoading, refetch: refetchFinance } = useQuery({
    queryKey: ['mp-analytics-finance-summary'],
    queryFn: async () => {
      const thirtyDaysAgo = subDays(new Date(), 30).toISOString().split('T')[0];
      const today = new Date().toISOString().split('T')[0];
      const { data, error } = await supabase
        .from('marketplace_finance_summary')
        .select('*')
        .gte('period_date', thirtyDaysAgo)
        .lte('period_date', today)
        .eq('period_type', 'daily');
      if (error) throw error;
      return data || [];
    },
    staleTime: 60000,
  });

  // Lightweight: pending count only
  const { data: pendingCount } = useQuery({
    queryKey: ['mp-analytics-pending-count'],
    queryFn: async () => {
      const { count, error } = await supabase
        .from('marketplace_orders')
        .select('*', { count: 'exact', head: true })
        .in('fulfillment_status', ['pending', 'CREATED']);
      if (error) throw error;
      return count || 0;
    },
    staleTime: 60000,
  });

  // Fetch listings for product analytics
  const { data: listings, isLoading: listingsLoading } = useQuery({
    queryKey: ['marketplace-listings-analytics'],
    queryFn: async () => {
      return await fetchAllRows(
        supabase
          .from('marketplace_listings')
          .select(`
            id, title, price, stock, status, product_rank, store_id, external_sku,
            marketplace_stores(name, platform)
          `)
      );
    },
  });

  // Listings count queries
  const { data: listingsCount } = useQuery({
    queryKey: ['marketplace-listings-count'],
    queryFn: async () => {
      const [activeResult, lowStockResult, outOfStockResult] = await Promise.all([
        supabase.from('marketplace_listings').select('*', { count: 'exact', head: true }).eq('status', 'active'),
        supabase.from('marketplace_listings').select('*', { count: 'exact', head: true }).gt('stock', 0).lt('stock', 5),
        supabase.from('marketplace_listings').select('*', { count: 'exact', head: true }).eq('stock', 0).eq('status', 'active'),
      ]);
      return {
        activeCount: activeResult.count || 0,
        lowStockCount: lowStockResult.count || 0,
        outOfStockCount: outOfStockResult.count || 0,
      };
    },
  });

  // === Platform store splits ===
  const uzumStores = useMemo(() => stores?.filter(s => s.platform === 'uzum') || [], [stores]);
  const yandexStores = useMemo(() => stores?.filter(s => s.platform === 'yandex') || [], [stores]);

  const platformStores = useMemo(() => {
    if (platformTab === 'uzum') return uzumStores;
    if (platformTab === 'yandex') return yandexStores;
    return stores || [];
  }, [platformTab, stores, uzumStores, yandexStores]);

  // === Filter summary by platform ===
  const summary = financeSummary || [];

  const platformSummary = useMemo(() => {
    let filtered = summary;
    if (platformTab !== 'all') {
      const platformStoreIds = new Set(
        (platformTab === 'uzum' ? uzumStores : yandexStores).map(s => s.id)
      );
      filtered = filtered.filter(r => platformStoreIds.has(r.store_id));
    }
    if (selectedStoreId) {
      filtered = filtered.filter(r => r.store_id === selectedStoreId);
    }
    return filtered;
  }, [platformTab, selectedStoreId, summary, uzumStores, yandexStores]);

  // === Filterlangan listings (platform + store bo'yicha) ===
  const filteredListingsForKPI = useMemo(() => {
    if (!listings) return [];
    let result = listings;
    if (platformTab !== 'all') {
      result = result.filter(l => (l.marketplace_stores as any)?.platform === platformTab);
    }
    if (selectedStoreId) {
      result = result.filter(l => l.store_id === selectedStoreId);
    }
    return result;
  }, [listings, platformTab, selectedStoreId]);

  const filteredActiveListings = filteredListingsForKPI.filter(l => l.status === 'active').length;
  const filteredLowStock = filteredListingsForKPI.filter(l => (l.stock ?? 0) > 0 && (l.stock ?? 0) < 5).length;
  const filteredOutOfStock = filteredListingsForKPI.filter(l => (l.stock ?? 0) === 0 && l.status === 'active').length;

  // === Compute KPIs from filtered summary ===
  const analytics = useMemo(() => ({
    totalRevenue: platformSummary.reduce((s, r) => s + (r.gross_revenue || 0), 0),
    totalCommission: platformSummary.reduce((s, r) => s + (r.commission_total || 0), 0),
    totalOrders: platformSummary.reduce((s, r) => s + (r.orders_count || 0), 0),
    completedOrders: platformSummary.reduce((s, r) => s + (r.delivered_count || 0), 0),
    cancelledOrders: platformSummary.reduce((s, r) => s + (r.cancelled_count || 0), 0),
    returnedOrders: platformSummary.reduce((s, r) => s + (r.returned_count || 0), 0),
    pendingOrders: pendingCount || 0,
    activeListings: filteredActiveListings,
    lowStockListings: filteredLowStock,
    outOfStockListings: filteredOutOfStock,
  }), [platformSummary, pendingCount, filteredActiveListings, filteredLowStock, filteredOutOfStock]);

  const netRevenue = analytics.totalRevenue - analytics.totalCommission;

  // === Revenue trend from filtered summary (group by period_date) ===
  const trendData = useMemo(() => {
    const trendByDate: Record<string, { revenue: number; orders: number }> = {};
    for (const row of platformSummary) {
      const date = format(new Date(row.period_date + 'T00:00:00'), 'MM-dd');
      if (!trendByDate[date]) trendByDate[date] = { revenue: 0, orders: 0 };
      trendByDate[date].revenue += row.gross_revenue || 0;
      trendByDate[date].orders += row.delivered_count || 0;
    }
    return Object.entries(trendByDate)
      .map(([date, data]) => ({ date, ...data }))
      .sort((a, b) => a.date.localeCompare(b.date))
      .slice(-14);
  }, [platformSummary]);

  // === Base store revenue for chips (platform filtered, NOT store filtered) ===
  const baseStoreRevenue = useMemo(() => {
    let filtered = summary;
    if (platformTab !== 'all') {
      const platformStoreIds = new Set(
        (platformTab === 'uzum' ? uzumStores : yandexStores).map(s => s.id)
      );
      filtered = filtered.filter(r => platformStoreIds.has(r.store_id));
    }
    const map: Record<string, number> = {};
    for (const row of filtered) {
      map[row.store_id] = (map[row.store_id] || 0) + (row.gross_revenue || 0);
    }
    return map;
  }, [platformTab, summary, uzumStores, yandexStores]);

  // === Base store orders for mini cards (platform filtered, NOT store filtered) ===
  const baseStoreOrders = useMemo(() => {
    let filtered = summary;
    if (platformTab !== 'all') {
      const platformStoreIds = new Set(
        (platformTab === 'uzum' ? uzumStores : yandexStores).map(s => s.id)
      );
      filtered = filtered.filter(r => platformStoreIds.has(r.store_id));
    }
    const map: Record<string, number> = {};
    for (const row of filtered) {
      map[row.store_id] = (map[row.store_id] || 0) + (row.orders_count || 0);
    }
    return map;
  }, [platformTab, summary, uzumStores, yandexStores]);

  // === Store distribution — ALL platform stores, including those with 0 revenue ===
  const storeChartData = useMemo(() => {
    if (platformTab === 'all') {
      const revenueByStoreId: Record<string, number> = {};
      for (const row of platformSummary) {
        revenueByStoreId[row.store_id] = (revenueByStoreId[row.store_id] || 0) + (row.gross_revenue || 0);
      }
      return Object.entries(revenueByStoreId)
        .map(([storeId, value]) => ({
          storeId,
          name: stores?.find(s => s.id === storeId)?.name || 'Unknown',
          value,
        }))
        .sort((a, b) => b.value - a.value);
    }
    return platformStores
      .map(store => ({
        storeId: store.id,
        name: store.name,
        value: baseStoreRevenue[store.id] || 0,
      }))
      .sort((a, b) => b.value - a.value);
  }, [platformTab, platformSummary, platformStores, baseStoreRevenue, stores]);

  // === Uzum & Yandex separate chart data ===
  const uzumChartData = useMemo(() => {
    const uzumStoreIds = new Set(uzumStores.map(s => s.id));
    const revenueByStoreId: Record<string, number> = {};
    for (const row of summary) {
      if (uzumStoreIds.has(row.store_id)) {
        revenueByStoreId[row.store_id] = (revenueByStoreId[row.store_id] || 0) + (row.gross_revenue || 0);
      }
    }
    return uzumStores
      .map(store => ({
        storeId: store.id,
        name: store.name,
        value: revenueByStoreId[store.id] || 0,
      }))
      .sort((a, b) => b.value - a.value);
  }, [uzumStores, summary]);

  const yandexChartData = useMemo(() => {
    const yandexStoreIds = new Set(yandexStores.map(s => s.id));
    const revenueByStoreId: Record<string, number> = {};
    for (const row of summary) {
      if (yandexStoreIds.has(row.store_id)) {
        revenueByStoreId[row.store_id] = (revenueByStoreId[row.store_id] || 0) + (row.gross_revenue || 0);
      }
    }
    return yandexStores
      .map(store => ({
        storeId: store.id,
        name: store.name,
        value: revenueByStoreId[store.id] || 0,
      }))
      .sort((a, b) => b.value - a.value);
  }, [yandexStores, summary]);

  // === Per-store revenue & orders map (from filtered platformSummary, for KPI cards) ===
  const storeRevenue = useMemo(() => {
    const map: Record<string, number> = {};
    for (const row of platformSummary) {
      map[row.store_id] = (map[row.store_id] || 0) + (row.gross_revenue || 0);
    }
    return map;
  }, [platformSummary]);

  const storeOrders = useMemo(() => {
    const map: Record<string, number> = {};
    for (const row of platformSummary) {
      map[row.store_id] = (map[row.store_id] || 0) + (row.orders_count || 0);
    }
    return map;
  }, [platformSummary]);

  // Product rank distribution
  const rankDistribution = listings?.reduce((acc: Record<string, number>, l) => {
    const rank = l.product_rank || 'N';
    acc[rank] = (acc[rank] || 0) + 1;
    return acc;
  }, {}) || {};

  const rankChartData = ['A', 'B', 'C', 'D', 'N'].map(rank => ({
    name: rank === 'N' ? t('mpa_rank_new') : `${rank}-Rank`,
    value: rankDistribution[rank] || 0,
    fill: rank === 'A' ? '#22c55e' : rank === 'B' ? '#3b82f6' : rank === 'C' ? '#eab308' : rank === 'D' ? '#ef4444' : '#94a3b8',
  }));

  const topProducts = listings?.filter(l => l.product_rank === 'A').slice(0, 5) || [];
  const worstProducts = listings?.filter(l => l.product_rank === 'D' || (l.stock === 0 && l.status === 'active')).slice(0, 5) || [];

  const handleRefresh = async () => {
    setIsRefreshing(true);
    try {
      await refetchFinance();
      toast.success(t('mp_data_refreshed'));
    } catch (error) {
      toast.error(t('mp_refresh_error'));
    }
    setIsRefreshing(false);
  };

  const formatCurrency = (amount: number) => {
    return new Intl.NumberFormat('uz-UZ').format(Math.round(amount)) + ' UZS';
  };

  // Platform color config
  const platformConfig = {
    all: { color: 'text-primary', bg: 'bg-primary/10', label: 'Barchasi' },
    uzum: { color: 'text-purple-500', bg: 'bg-purple-500/10', label: 'Uzum' },
    yandex: { color: 'text-yellow-500', bg: 'bg-yellow-500/10', label: 'Yandex Market' },
  };
  const cfg = platformConfig[platformTab];

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-3">
        <div>
          <h1 className="text-xl sm:text-2xl font-bold flex items-center gap-2">
            <Brain className="h-5 w-5 sm:h-6 sm:w-6 text-primary" />
            {t('mpa_title')}
          </h1>
          <p className="text-muted-foreground text-sm">
            {t('mpa_subtitle')}
          </p>
        </div>
        <Button onClick={handleRefresh} variant="outline" disabled={isRefreshing} className="w-full sm:w-auto min-h-[44px]">
          <RefreshCw className={`h-4 w-4 mr-2 ${isRefreshing ? 'animate-spin' : ''}`} />
          {t('mpa_refresh')}
        </Button>
      </div>

      {/* Platform Tabs */}
      <div className="space-y-3">
        <div className="flex gap-2 flex-wrap">
          {(['all', 'uzum', 'yandex'] as PlatformTab[]).map((pt) => {
            const pcfg = platformConfig[pt];
            const isActive = platformTab === pt;
            return (
              <button
                key={pt}
                onClick={() => {
                  setPlatformTab(pt);
                  setSelectedStoreId(null);
                }}
                className={`px-4 py-2 rounded-full text-sm font-medium border transition-all ${isActive
                  ? `${pcfg.bg} ${pcfg.color} border-current`
                  : 'border-border text-muted-foreground hover:border-muted-foreground/50'
                  }`}
              >
                {pt === 'all' ? '🌐 Barchasi' : pt === 'uzum' ? '🟣 Uzum' : '🟡 Yandex Market'}
                {pt !== 'all' && (
                  <span className="ml-1.5 opacity-60 text-xs">
                    ({pt === 'uzum' ? uzumStores.length : yandexStores.length} do'kon)
                  </span>
                )}
              </button>
            );
          })}
        </div>

        {/* Store chips — shown only when uzum or yandex is selected */}
        {platformTab !== 'all' && platformStores.length > 0 && (
          <div className="flex flex-wrap gap-2 pl-1">
            {/* "Barchasi" chip */}
            <button
              onClick={() => setSelectedStoreId(null)}
              className={`px-3 py-1.5 rounded-lg text-xs font-medium border transition-all ${!selectedStoreId
                ? 'bg-muted border-foreground/30 text-foreground'
                : 'border-border text-muted-foreground hover:border-muted-foreground/50'
                }`}
            >
              Barchasi ({platformStores.length})
            </button>

            {/* Individual store chips */}
            {platformStores.map(store => {
              const rev = baseStoreRevenue[store.id] || 0;
              const isSelected = selectedStoreId === store.id;
              return (
                <button
                  key={store.id}
                  onClick={() => setSelectedStoreId(isSelected ? null : store.id)}
                  className={`px-3 py-1.5 rounded-lg text-xs font-medium border transition-all ${isSelected
                    ? `${cfg.bg} ${cfg.color} border-current`
                    : 'border-border text-muted-foreground hover:border-muted-foreground/50'
                    }`}
                >
                  {store.name}
                  {rev > 0 && (
                    <span className="ml-1 opacity-60">
                      {(rev / 1_000_000).toFixed(0)}M
                    </span>
                  )}
                </button>
              );
            })}
          </div>
        )}
      </div>

      {/* Selected store badge */}
      {selectedStoreId && (() => {
        const selectedStore = stores?.find(s => s.id === selectedStoreId);
        if (!selectedStore) return null;
        const isUzum = selectedStore.platform === 'uzum';
        return (
          <div className="flex items-center gap-2">
            <Badge variant="outline" className={`${isUzum ? 'border-purple-500/50 text-purple-600' : 'border-yellow-500/50 text-yellow-600'}`}>
              {isUzum ? '🟣' : '🟡'} {selectedStore.name}
              <button
                className="ml-1.5 hover:opacity-70"
                onClick={() => setSelectedStoreId(null)}
              >
                ✕
              </button>
            </Badge>
          </div>
        );
      })()}

      {/* Quick Stats */}
      <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
        <Card>
          <CardContent className="pt-4">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-sm text-muted-foreground">{t('mpa_total_revenue')}</p>
                <p className="text-2xl font-bold">{formatCurrency(netRevenue)}</p>
                <p className="text-xs text-muted-foreground">{cfg.label} • {t('mpa_last_30_days')}</p>
              </div>
              <DollarSign className="h-8 w-8 text-green-500 opacity-80" />
            </div>
          </CardContent>
        </Card>

        <Card>
          <CardContent className="pt-4">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-sm text-muted-foreground">{t('mpa_total_orders')}</p>
                <p className="text-2xl font-bold">{analytics.totalOrders}</p>
                <div className="flex gap-2 text-xs">
                  <span className="text-green-600">{analytics.completedOrders} ✓</span>
                  <span className="text-yellow-600">{analytics.pendingOrders} ⏳</span>
                </div>
              </div>
              <ShoppingCart className="h-8 w-8 text-blue-500 opacity-80" />
            </div>
          </CardContent>
        </Card>

        <Card>
          <CardContent className="pt-4">
            <div className="flex items-center justify-between">
