                  <div className="text-center py-8 text-muted-foreground">
                    <Package className="h-8 w-8 mx-auto mb-2 opacity-50" />
                    <p className="text-sm">Tayyor qutilar topilmadi</p>
                    <p className="text-xs">Avval qutilarni muhrlang (seal qiling)</p>
                  </div>
                )}
              </ScrollArea>
            </div>
          </div>

          <div className="flex justify-end gap-3 mt-4 pt-4 border-t border-border">
            <Button variant="outline" onClick={() => setCreateDialogOpen(false)}>Bekor qilish</Button>
            <Button
              onClick={() => createShipmentMutation.mutate()}
              disabled={createShipmentMutation.isPending || !isFormValid()}
              className="bg-gradient-to-r from-primary to-secondary"
            >
              {createShipmentMutation.isPending ? 'Yaratilmoqda...' : 'Yaratish'}
            </Button>
          </div>
        </DialogContent>
      </Dialog>

      {/* Edit Shipment Dialog */}
      <Dialog open={editDialogOpen} onOpenChange={setEditDialogOpen}>
        <DialogContent className="bg-card border-border max-w-lg w-[95vw]">
          <DialogHeader>
            <DialogTitle className="text-foreground">Jo'natmani Tahrirlash</DialogTitle>
          </DialogHeader>
          <div className="space-y-4">
            <div>
              <label className="text-sm font-medium text-foreground mb-2 block">Jo'natma raqami</label>
              <Input
                value={formData.shipment_number}
                disabled
                className="bg-muted border-border"
              />
            </div>

            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
              <div>
                <label className="text-sm font-medium text-foreground mb-2 block">Tashuvchi</label>
                <Select value={formData.carrier} onValueChange={(value) => setFormData({ ...formData, carrier: value })}>
                  <SelectTrigger className="bg-input border-border">
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent className="bg-card border-border">
                    <SelectItem value="AbuSaxiy">AbuSaxiy</SelectItem>
                    <SelectItem value="Other">Boshqa</SelectItem>
                  </SelectContent>
                </Select>
              </div>

              <div>
                <label className="text-sm font-medium text-foreground mb-2 block">Tracking raqami</label>
                <Input
                  placeholder="Track raqami"
                  value={formData.tracking_number}
                  onChange={(e) => setFormData({ ...formData, tracking_number: e.target.value })}
                  className="bg-input border-border"
                />
              </div>
            </div>

            <div>
              <label className="text-sm font-medium text-foreground mb-2 block">Holat</label>
              <Select value={formData.status} onValueChange={(value) => setFormData({ ...formData, status: value })}>
                <SelectTrigger className="bg-input border-border">
                  <SelectValue />
                </SelectTrigger>
                <SelectContent className="bg-card border-border">
                  <SelectItem value="pending">Kutilmoqda</SelectItem>
                  <SelectItem value="in_transit">Yo'lda</SelectItem>
                  <SelectItem value="arrived">Yetib keldi</SelectItem>
                  <SelectItem value="delivered">Topshirildi</SelectItem>
                </SelectContent>
              </Select>
            </div>

            <div>
              <label className="text-sm font-medium text-foreground mb-2 block">Izoh</label>
              <Textarea
                placeholder="Qo'shimcha ma'lumotlar..."
                value={formData.notes}
                onChange={(e) => setFormData({ ...formData, notes: e.target.value })}
                className="bg-input border-border min-h-[80px]"
              />
            </div>
          </div>

          <div className="flex justify-end gap-3 mt-4">
            <Button variant="outline" onClick={() => setEditDialogOpen(false)}>Bekor qilish</Button>
            <Button
              onClick={() => updateShipmentMutation.mutate()}
              disabled={updateShipmentMutation.isPending}
              className="bg-gradient-to-r from-primary to-secondary"
            >
              {updateShipmentMutation.isPending ? 'Saqlanmoqda...' : 'Saqlash'}
            </Button>
          </div>
        </DialogContent>
      </Dialog>

      <ConfirmDialog
        open={deleteDialogOpen}
        onOpenChange={setDeleteDialogOpen}
        title="Jo'natmani o'chirish"
        description={`"${shipmentToDelete?.shipment_number}" jo'natmasini o'chirishni xohlaysizmi? Bu amalni ortga qaytarib bo'lmaydi.`}
        confirmText="O'chirish"
        cancelText="Bekor qilish"
        variant="destructive"
        onConfirm={() => {
          if (shipmentToDelete) {
            deleteShipmentMutation.mutate(shipmentToDelete.id);
          }
        }}
      />
    </div>
  );
}

import React, { useState } from 'react';
import { useQuery } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/components/ui/card';
import { Store, TrendingDown, TrendingUp, AlertTriangle, AlertCircle, RefreshCw, DollarSign, Package } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Skeleton } from '@/components/ui/skeleton';
import { Badge } from '@/components/ui/badge';
import { format, startOfMonth, endOfMonth } from 'date-fns';
import { useFinanceCurrency } from '@/contexts/FinanceCurrencyContext';
import { fetchAllRows } from '@/lib/fetchAllRows';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import CompetitorAnalysis from '@/components/analytics/CompetitorAnalysis';

const num = (val: any) => {
    if (!val) return 0;
    const n = Number(val);
    return isNaN(n) ? 0 : n;
};

export default function StoreAnalytics() {
    const [isRefreshing, setIsRefreshing] = useState(false);
    const { cnyToUzs, usdToUzs, isRatesLoading } = useFinanceCurrency();

    const today = new Date();
    const startDate = format(startOfMonth(today), 'yyyy-MM-dd');
    const endDate = format(endOfMonth(today), 'yyyy-MM-dd') + 'T23:59:59';
    const displayPeriod = `${format(startOfMonth(today), 'dd.MM.yyyy')} - ${format(today, 'dd.MM.yyyy')}`;

    const { data: analyticsData, isLoading, error, refetch } = useQuery({
        queryKey: ['store-analytics-comprehensive', startDate, endDate, cnyToUzs, usdToUzs],
        enabled: !isRatesLoading && cnyToUzs > 0,
        queryFn: async () => {
            const { data: storesList, error: storesError } = await supabase
                .from('marketplace_stores')
                .select('*')
                .order('name');
            if (storesError) throw storesError;

            const stores = storesList || [];
            if (stores.length === 0) return { stores: [], totalRevenue: 0, totalProfit: 0 };
            const storeIds = stores.map(s => s.id);

            // Fetch all delivered orders for the period
            const orders = await fetchAllRows(
                supabase.from('marketplace_orders')
                    .select('store_id, items, total_amount')
                    .in('store_id', storeIds)
                    .eq('fulfillment_status', 'delivered')
                    .gte('delivered_at', startDate)
                    .lte('delivered_at', endDate)
            );

            // Extract unique SKUs and tally quantities per store
            const storeSkuStats: Record<string, Record<string, { qty: number, revenue: number, comm: number }>> = {};
            const uniqueSkus = new Set<string>();

            orders.forEach(order => {
                const storeId = order.store_id;
                if (!storeSkuStats[storeId]) storeSkuStats[storeId] = {};

                if (order.items && Array.isArray(order.items)) {
                    order.items.forEach(item => {
                        const sku = item.skuTitle || item.offerId;
                        if (!sku) return;

                        uniqueSkus.add(sku);
                        if (!storeSkuStats[storeId][sku]) {
                            storeSkuStats[storeId][sku] = { qty: 0, revenue: 0, comm: 0 };
                        }

                        const qty = num(item.quantity) || 1;
                        storeSkuStats[storeId][sku].qty += qty;
                        storeSkuStats[storeId][sku].revenue += num(item.price) * qty;
                        storeSkuStats[storeId][sku].comm += (num(item.commission) || (num(item.price) * qty * 0.2));
                    });
                }
            });

            const skusArray = Array.from(uniqueSkus);

            // Fetch mappings and listings
            const skuMappings = skusArray.length > 0 ? await fetchAllRows(
                supabase.from('variant_sku_mappings').select('external_sku, variant_id').in('external_sku', skusArray)
            ) : [];

            const listings = skusArray.length > 0 ? await fetchAllRows(
                supabase.from('marketplace_listings').select('external_sku, external_offer_id, title, product_id, price').in('store_id', storeIds)
            ) : [];

            const resolvedMapping: Record<string, { variantId?: string; productId?: string, listingPrice?: number }> = {};

            skuMappings.forEach((m: any) => {
                resolvedMapping[m.external_sku] = { variantId: m.variant_id };
            });

            skusArray.forEach(sku => {
                if (!resolvedMapping[sku] || (!resolvedMapping[sku].variantId && !resolvedMapping[sku].productId)) {
                    const matched = listings.find(l => l.external_sku === sku || l.external_offer_id === sku || l.title === sku);
                    if (matched) {
                        resolvedMapping[sku] = { productId: matched.product_id, listingPrice: num(matched.price) };
                    }
                }
            });

            const variantIds = [...new Set(Object.values(resolvedMapping).map(m => m.variantId).filter(Boolean))] as string[];
            let productIds = [...new Set(Object.values(resolvedMapping).map(m => m.productId).filter(Boolean))] as string[];

            // Fetch cost and cargo data
            const variantsMap: Record<string, { cost: number, currency: string, pId: string }> = {};
            if (variantIds.length > 0) {
                const variants = await fetchAllRows(
                    supabase.from('product_variants').select('id, cost_price, cost_price_currency, product_id').in('id', variantIds)
                );
                variants.forEach(v => {
                    variantsMap[v.id] = { cost: num(v.cost_price), currency: v.cost_price_currency || 'UZS', pId: v.product_id };
                    if (v.product_id && !productIds.includes(v.product_id)) productIds.push(v.product_id);
                });
            }

            const productsMap: Record<string, { cost: number, shipToChina: number, qty: number }> = {};
            if (productIds.length > 0) {
                const productsList = await fetchAllRows(
                    supabase.from('products').select('id, cost_price, shipping_cost_to_china, quantity').in('id', productIds)
                );
                productsList.forEach(p => {
                    productsMap[p.id] = { cost: num(p.cost_price), shipToChina: num(p.shipping_cost_to_china), qty: Math.max(num(p.quantity), 1) };
                });
            }

            const avgShipping: Record<string, { dom: number, intl: number, count: number }> = {};
            if (productIds.length > 0) {
                const pItems = await fetchAllRows(
                    supabase.from('product_items')
                        .select('product_id, variant_id, domestic_shipping_cost, international_shipping_cost')
                        .in('product_id', productIds)
                );
                pItems.forEach(item => {
                    const keys = [item.variant_id, item.product_id].filter(Boolean) as string[];
                    keys.forEach(k => {
                        if (!avgShipping[k]) avgShipping[k] = { dom: 0, intl: 0, count: 0 };
                        avgShipping[k].dom += num(item.domestic_shipping_cost);
                        avgShipping[k].intl += num(item.international_shipping_cost);
                        avgShipping[k].count += 1;
                    });
                });
            }

            // Calculate store totals
            const storeResults = stores.map(store => {
                let totalRevenue = 0;
                let totalCost = 0;
                let totalSales = 0;
                let pureCommission = 0;

                const stats = storeSkuStats[store.id] || {};

                Object.entries(stats).forEach(([sku, metric]) => {
                    totalRevenue += metric.revenue;
                    pureCommission += metric.comm;
                    totalSales += metric.qty;

                    const map = resolvedMapping[sku] || {};
                    const vId = map.variantId;
                    const pId = map.productId;

                    // China price calc
                    let chinaPrice = 0;
                    const v = vId ? variantsMap[vId] : null;
                    const p = pId ? productsMap[pId] : null;

                    if (v && v.cost > 0) {
                        if (v.currency === 'CNY') chinaPrice = v.cost * cnyToUzs;
                        else if (v.currency === 'USD') chinaPrice = v.cost * usdToUzs;
                        else chinaPrice = v.cost;
                    } else if (p && p.cost > 0) {
                        chinaPrice = p.cost;
                    } else if (map.listingPrice) {
                        chinaPrice = map.listingPrice * 0.4; // fallback estimation 40%
                    }

                    // Cargo price calc
                    let cargoPrice = 0;
                    let dCny = 0, iUsd = 0;
                    const s = (vId ? avgShipping[vId] : null) || (pId ? avgShipping[pId] : null);

                    if (s && s.count > 0) {
                        dCny = s.dom / s.count;
                        iUsd = s.intl / s.count;
                    } else if (p && p.shipToChina > 0) {
                        dCny = p.shipToChina / p.qty;
                    }

                    cargoPrice = (dCny * cnyToUzs) + (iUsd * usdToUzs);
                    const tanNarx = (chinaPrice + cargoPrice) * metric.qty;
                    totalCost += tanNarx;
                });

                const totalExpenses = totalCost + pureCommission;
                const profit = totalRevenue - totalExpenses;
                const margin = totalRevenue > 0 ? (profit / totalRevenue) * 100 : 0;

                const isLoss = profit < 0;
                const isLowRevenue = totalRevenue > 0 && totalRevenue < 500000;

                return {
                    ...store,
                    totalRevenue,
                    totalExpenses,
                    profit,
                    margin,
                    totalSales,
                    isLoss,
                    isLowRevenue
                };
            });

            storeResults.sort((a, b) => b.profit - a.profit);
            const tRev = storeResults.reduce((sum, s) => sum + s.totalRevenue, 0);
            const tProf = storeResults.reduce((sum, s) => sum + s.profit, 0);

            return { stores: storeResults, totalRevenue: tRev, totalProfit: tProf };
        }
    });

    const handleRefresh = async () => {
        setIsRefreshing(true);
        await refetch();
        setIsRefreshing(false);
    };

    const fmt = (v: number) => new Intl.NumberFormat('uz-UZ').format(Math.round(v)) + " so'm";

    return (
        <div className="p-4 md:p-6 space-y-6 animate-fade-in max-w-[1600px] mx-auto">
            <div className="flex flex-col gap-2 md:flex-row md:items-center md:justify-between">
                <div>
                    <h1 className="text-3xl font-bold tracking-tight text-slate-900 dark:text-slate-100 flex items-center gap-2">
                        <Store className="h-8 w-8 text-primary" />
                        Umumiy Do'konlar Analitikasi
                    </h1>
                    <p className="text-muted-foreground mt-1 text-sm md:text-base">
                        Barcha ulangan do'konlaringiz oylik foyda va ziyonlari bitta joyda ({displayPeriod})
                    </p>
                </div>

                <div className="flex items-center gap-3">
                    <Button onClick={handleRefresh} disabled={isRefreshing || isLoading || isRatesLoading} className="shadow-sm transition-all hover:shadow-md">
                        <RefreshCw className={`h-4 w-4 mr-2 ${isRefreshing ? "animate-spin" : ""}`} />
                        Yangilash
                    </Button>
                </div>
            </div>

            <Tabs defaultValue="my-stores" className="w-full mt-4">
                <TabsList className="mb-6 h-11 bg-slate-100/50 dark:bg-slate-900/50 p-1 rounded-lg">
                    <TabsTrigger value="my-stores" className="px-6 h-9 rounded-md">Mening Do'konlarim</TabsTrigger>
                    <TabsTrigger value="competitors" className="px-6 h-9 rounded-md">Raqobatchilar (Uzum.uz)</TabsTrigger>
                </TabsList>

                <TabsContent value="my-stores" className="space-y-6">
                    {error && (
                        <div className="bg-destructive/10 border border-destructive/20 text-destructive p-4 rounded-lg">
                            Xatolik yuz berdi: {(error as Error).message}
                        </div>
                    )}
                    <div className="grid gap-4 md:gap-6 md:grid-cols-3">
                        {isLoading || isRatesLoading ? (
                            Array(3).fill(0).map((_, i) => (
                                <Card key={i} className="shadow-sm border-slate-200 dark:border-slate-800">
                                    <CardHeader className="pb-2"><Skeleton className="h-4 w-24" /></CardHeader>
                                    <CardContent><Skeleton className="h-8 w-32" /></CardContent>
                                </Card>
                            ))
                        ) : (
                            <>
                                <Card className="shadow-sm border-slate-200 dark:border-slate-800">
                                    <CardHeader className="flex flex-row items-center justify-between pb-2 space-y-0">
                                        <CardTitle className="text-sm font-medium text-muted-foreground">Jami Tushum ({displayPeriod})</CardTitle>
                                        <div className="p-2 bg-emerald-100 dark:bg-emerald-900/30 rounded-full">
                                            <DollarSign className="h-4 w-4 text-emerald-600 dark:text-emerald-400" />
                                        </div>
                                    </CardHeader>
                                    <CardContent>
                                        <div className="text-2xl font-bold">{fmt(analyticsData?.totalRevenue || 0)}</div>
                                    </CardContent>
                                </Card>
                                <Card className="shadow-sm border-slate-200 dark:border-slate-800">
                                    <CardHeader className="flex flex-row items-center justify-between pb-2 space-y-0">
                                        <CardTitle className="text-sm font-medium text-muted-foreground">Sof Foyda (Tannarx va Kargo olingan)</CardTitle>
                                        <div className="p-2 bg-primary/10 rounded-full">
                                            <TrendingUp className="h-4 w-4 text-primary" />
                                        </div>
                                    </CardHeader>
                                    <CardContent>
                                        <div className={`text-2xl font-bold ${(analyticsData?.totalProfit || 0) < 0 ? 'text-destructive' : 'text-emerald-600 dark:text-emerald-400'}`}>
                                            {fmt(analyticsData?.totalProfit || 0)}
                                        </div>
                                    </CardContent>
                                </Card>
                                <Card className="shadow-sm border-slate-200 dark:border-slate-800">
                                    <CardHeader className="flex flex-row items-center justify-between pb-2 space-y-0">
                                        <CardTitle className="text-sm font-medium text-muted-foreground">Oylik Buyurtmalar (yetkazilgan)</CardTitle>
                                        <div className="p-2 bg-sky-100 dark:bg-sky-900/30 rounded-full">
                                            <Package className="h-4 w-4 text-sky-600 dark:text-sky-400" />
                                        </div>
                                    </CardHeader>
                                    <CardContent>
                                        <div className="text-2xl font-bold">
                                            {analyticsData?.stores.reduce((sum, s) => sum + s.totalSales, 0) || 0} dona
                                        </div>
                                    </CardContent>
                                </Card>
                            </>
                        )}
                    </div>

                    {(!isLoading && !isRatesLoading && analyticsData?.stores.length) ? (
                        <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 mt-6">
                            {analyticsData.stores.map(store => (
                                <Card
                                    key={store.id}
                                    className={`overflow-hidden transition-all hover:shadow-md ${store.isLoss ? 'border-destructive/60 bg-red-50/50 dark:bg-red-950/20' : store.isLowRevenue ? 'border-amber-400/60 bg-amber-50/30 dark:bg-amber-950/20' : 'border-slate-200 dark:border-slate-800'}`}
                                >
                                    <CardHeader className={`pb-3 border-b ${store.isLoss ? 'bg-red-100/50 dark:bg-red-900/40' : store.isLowRevenue ? 'bg-amber-100/50 dark:bg-amber-900/40' : 'bg-slate-50/50 dark:bg-slate-900/50'}`}>
                                        <div className="flex justify-between items-start">
                                            <div>
                                                <CardTitle className="text-lg line-clamp-1 flex items-center gap-2">
                                                    {store.name}
                                                    {store.isLoss && <AlertTriangle className="h-4 w-4 text-destructive shrink-0" />}
                                                    {store.isLowRevenue && !store.isLoss && <AlertCircle className="h-4 w-4 text-amber-500 shrink-0" />}
                                                </CardTitle>
                                                <CardDescription className="uppercase mt-1 text-xs font-semibold">{store.platform}</CardDescription>
                                            </div>
                                        </div>
                                    </CardHeader>
                                    <CardContent className="pt-4 space-y-3">
                                        <div className="flex justify-between items-center text-sm">
                                            <span className="text-muted-foreground flex items-center gap-1.5"><DollarSign className="h-3.5 w-3.5" /> Tushum</span>
                                            <span className="font-semibold">{fmt(store.totalRevenue)}</span>
                                        </div>
                                        <div className="flex justify-between items-center text-sm">
                                            <span className="text-muted-foreground flex items-center gap-1.5"><TrendingDown className="h-3.5 w-3.5" /> Xarajat & Kargo</span>
                                            <span className="font-medium">{fmt(store.totalExpenses)}</span>
                                        </div>
                                        <div className="pt-2 border-t flex justify-between items-center">
                                            <span className="text-sm font-medium">Sof Foyda</span>
                                            <Badge variant={store.isLoss ? "destructive" : "default"} className={!store.isLoss ? "bg-emerald-500 hover:bg-emerald-600" : ""}>
                                                {store.profit > 0 ? "+" : ""}{fmt(store.profit)}
                                            </Badge>
                                        </div>
                                    </CardContent>
                                </Card>
                            ))}
                        </div>
                    ) : (
                        !isLoading && !isRatesLoading && (
                            <div className="text-center py-12 px-4 rounded-xl border border-dashed text-muted-foreground">
                                Do'konlar bo'yicha ma'lumot topilmadi yoki buyurtmalar yo'q.
                            </div>
                        )
                    )}
                </TabsContent>

                <TabsContent value="competitors">
                    <CompetitorAnalysis />
                </TabsContent>
            </Tabs>
        </div>
    );
}

import { useState } from 'react';
import { Card } from '@/components/ui/card';
import { Input } from '@/components/ui/input';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { 
  Search, Box, MapPin, CheckCircle, Clock, Truck, ShieldAlert, 
  Package, Ship, Calendar, Filter, BarChart3, TrendingUp
} from 'lucide-react';
import { useTranslation } from 'react-i18next';
import { useQuery } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';
import { fetchAllRows } from '@/lib/fetchAllRows';
import { LoadingSkeleton } from '@/components/ui/loading-skeleton';
import { useUserRole } from '@/hooks/useUserRole';

export default function Tracking() {
  const { t } = useTranslation();
  const [searchQuery, setSearchQuery] = useState('');
  const [eventTypeFilter, setEventTypeFilter] = useState<string>('all');
  const [locationFilter, setLocationFilter] = useState<string>('all');
  const [dateRange, setDateRange] = useState<string>('all');

  const { isChiefManager, isChinaManager, isChinaStaff, isUzManager, isUzStaff, isMarketplaceManager, isSupport, isLoading: roleLoading } = useUserRole();

  // Role-based access control - most staff can view tracking
  const canAccess = isChiefManager || isChinaManager || isChinaStaff || isUzManager || isUzStaff || isMarketplaceManager || isSupport;

  // Access denied check
  if (!roleLoading && !canAccess) {
    return (
      <div className="flex flex-col items-center justify-center min-h-[60vh] text-center">
        <ShieldAlert className="h-16 w-16 text-destructive mb-4" />
        <h2 className="text-xl font-semibold text-foreground mb-2">Ruxsat yo'q</h2>
        <p className="text-muted-foreground">Sizda kuzatuv sahifasiga kirish huquqi yo'q.</p>
      </div>
    );
  }

  const { data: trackingEvents, isLoading } = useQuery({
    queryKey: ['tracking-events-boxes'],
    queryFn: async () => {
      // Get box tracking events with box details
      const events = await fetchAllRows(
        supabase
          .from('tracking_events')
          .select('*')
          .eq('entity_type', 'box')
          .order('created_at', { ascending: false })
      );

      // Get box numbers for display
      if (events && events.length > 0) {
        const boxIds = [...new Set(events.map((e: any) => e.entity_id))] as string[];
        const { data: boxes } = await supabase
          .from('boxes')
          .select('id, box_number')
          .in('id', boxIds);

        const boxMap = new Map(boxes?.map(b => [b.id, b.box_number]) || []);

        return events.map(event => ({
          ...event,
          box_number: boxMap.get(event.entity_id) || event.entity_id.slice(0, 8),
        }));
      }

      return events || [];
    },
  });

  // Fetch statistics
  const { data: stats } = useQuery({
    queryKey: ['tracking-stats'],
    queryFn: async () => {
      const now = new Date();
      const today = new Date(now.getFullYear(), now.getMonth(), now.getDate());
      const weekAgo = new Date(today.getTime() - 7 * 24 * 60 * 60 * 1000);

      // Get event counts
      const { data: allEvents } = await supabase
        .from('tracking_events')
        .select('id, event_type, created_at, location')
        .eq('entity_type', 'box');

      // Get box counts
      const { data: boxes } = await supabase
        .from('boxes')
        .select('id, status, location');

      const todayEvents = allEvents?.filter(e => new Date(e.created_at) >= today).length || 0;
      const weekEvents = allEvents?.filter(e => new Date(e.created_at) >= weekAgo).length || 0;

      const boxesByStatus = {
        packing: boxes?.filter(b => b.status === 'packing').length || 0,
        sealed: boxes?.filter(b => b.status === 'sealed').length || 0,
        in_transit: boxes?.filter(b => b.status === 'in_transit' || b.location === 'transit').length || 0,
        arrived: boxes?.filter(b => b.status === 'arrived').length || 0,
      };

      const boxesByLocation = {
        china: boxes?.filter(b => b.location === 'china').length || 0,
        transit: boxes?.filter(b => b.location === 'transit').length || 0,
        uzbekistan: boxes?.filter(b => b.location === 'uzbekistan').length || 0,
      };

      const eventsByType = {
        created: allEvents?.filter(e => e.event_type === 'created').length || 0,
        sealed: allEvents?.filter(e => e.event_type === 'sealed').length || 0,
        in_transit: allEvents?.filter(e => e.event_type === 'in_transit').length || 0,
        arrived: allEvents?.filter(e => e.event_type === 'arrived').length || 0,
        verified: allEvents?.filter(e => e.event_type === 'verified').length || 0,
      };

      return {
        totalEvents: allEvents?.length || 0,
        todayEvents,
        weekEvents,
        boxesByStatus,
        boxesByLocation,
        eventsByType,
      };
    },
  });

  const getEventIcon = (eventType: string) => {
    switch (eventType) {
      case 'created': return Box;
      case 'sealed': return Package;
      case 'in_transit': return Truck;
      case 'arrived': return CheckCircle;
      case 'delivered': return CheckCircle;
      case 'verified': return CheckCircle;
      default: return Clock;
    }
  };

  const getEventColor = (eventType: string) => {
    switch (eventType) {
      case 'created': return 'bg-blue-500/10 text-blue-500';
      case 'sealed': return 'bg-purple-500/10 text-purple-500';
      case 'in_transit': return 'bg-yellow-500/10 text-yellow-500';
      case 'arrived': return 'bg-green-500/10 text-green-500';
      case 'delivered': return 'bg-green-500/10 text-green-500';
      case 'verified': return 'bg-emerald-500/10 text-emerald-500';
      default: return 'bg-muted text-muted-foreground';
    }
  };

  // Filter events
  const filteredEvents = trackingEvents?.filter(event => {
    // Search filter
    if (searchQuery) {
      const query = searchQuery.toLowerCase();
      const matchesSearch = (
        event.entity_id.toLowerCase().includes(query) ||
        event.description?.toLowerCase().includes(query) ||
        event.location?.toLowerCase().includes(query) ||
        event.event_type.toLowerCase().includes(query) ||
        (event as any).box_number?.toLowerCase().includes(query)
      );
      if (!matchesSearch) return false;
    }

    // Event type filter
    if (eventTypeFilter !== 'all' && event.event_type !== eventTypeFilter) {
      return false;
    }

    // Location filter
    if (locationFilter !== 'all' && event.location !== locationFilter) {
      return false;
    }

    // Date range filter
    if (dateRange !== 'all') {
      const eventDate = new Date(event.created_at);
      const now = new Date();
      const today = new Date(now.getFullYear(), now.getMonth(), now.getDate());

      if (dateRange === 'today' && eventDate < today) return false;
      if (dateRange === 'week') {
        const weekAgo = new Date(today.getTime() - 7 * 24 * 60 * 60 * 1000);
        if (eventDate < weekAgo) return false;
      }
      if (dateRange === 'month') {
        const monthAgo = new Date(today.getTime() - 30 * 24 * 60 * 60 * 1000);
        if (eventDate < monthAgo) return false;
      }
    }

    return true;
  }) || [];

  return (
    <div className="space-y-6">
      <div>
        <h1 className="text-2xl sm:text-3xl font-bold text-foreground mb-2">
          {t('tracking')}
        </h1>
        <p className="text-muted-foreground text-sm sm:text-base">
          {t('trackingDescription')}
        </p>
      </div>

      {/* Statistics Cards */}
      <div className="grid grid-cols-2 sm:grid-cols-4 gap-4">
        <Card 
          className="p-4 bg-card border-border cursor-pointer hover:shadow-lg hover:border-primary/50 transition-all"
          onClick={() => { setEventTypeFilter('all'); setDateRange('all'); }}
        >
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 rounded-lg bg-primary/10 flex items-center justify-center">
              <BarChart3 className="h-5 w-5 text-primary" />
            </div>
            <div>
              <p className="text-2xl font-bold text-foreground">{stats?.totalEvents || 0}</p>
              <p className="text-xs text-muted-foreground">{t('totalEvents')}</p>
            </div>
          </div>
        </Card>

        <Card 
          className="p-4 bg-card border-border cursor-pointer hover:shadow-lg hover:border-green-500/50 transition-all"
          onClick={() => { setDateRange('today'); setEventTypeFilter('all'); }}
        >
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 rounded-lg bg-green-500/10 flex items-center justify-center">
              <TrendingUp className="h-5 w-5 text-green-500" />
            </div>
            <div>
              <p className="text-2xl font-bold text-foreground">{stats?.todayEvents || 0}</p>
              <p className="text-xs text-muted-foreground">{t('today')}</p>
            </div>
          </div>
        </Card>

        <Card 
          className="p-4 bg-card border-border cursor-pointer hover:shadow-lg hover:border-blue-500/50 transition-all"
          onClick={() => setEventTypeFilter('in_transit')}
        >
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 rounded-lg bg-blue-500/10 flex items-center justify-center">
              <Truck className="h-5 w-5 text-blue-500" />
            </div>
            <div>
              <p className="text-2xl font-bold text-foreground">{stats?.boxesByStatus.in_transit || 0}</p>
              <p className="text-xs text-muted-foreground">{t('inTransit')}</p>
            </div>
          </div>
        </Card>

        <Card 
          className="p-4 bg-card border-border cursor-pointer hover:shadow-lg hover:border-emerald-500/50 transition-all"
          onClick={() => setEventTypeFilter('arrived')}
        >
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 rounded-lg bg-emerald-500/10 flex items-center justify-center">
              <CheckCircle className="h-5 w-5 text-emerald-500" />
            </div>
            <div>
              <p className="text-2xl font-bold text-foreground">{stats?.boxesByStatus.arrived || 0}</p>
              <p className="text-xs text-muted-foreground">{t('arrived')}</p>
            </div>
          </div>
        </Card>
      </div>

      {/* Box Status Distribution */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        <Card className="p-4 bg-card border-border">
          <h3 className="text-sm font-medium text-foreground mb-3 flex items-center gap-2">
            <Package className="h-4 w-4" />
            {t('boxStatus')}
          </h3>
          <div className="space-y-2">
            <div className="flex items-center justify-between">
              <span className="text-sm text-muted-foreground">{t('packing')}</span>
              <Badge className="bg-purple-500/10 text-purple-500">{stats?.boxesByStatus.packing || 0}</Badge>
            </div>
            <div className="flex items-center justify-between">
              <span className="text-sm text-muted-foreground">{t('sealed')}</span>
              <Badge className="bg-blue-500/10 text-blue-500">{stats?.boxesByStatus.sealed || 0}</Badge>
            </div>
            <div className="flex items-center justify-between">
              <span className="text-sm text-muted-foreground">{t('inTransit')}</span>
              <Badge className="bg-yellow-500/10 text-yellow-500">{stats?.boxesByStatus.in_transit || 0}</Badge>
            </div>
            <div className="flex items-center justify-between">
              <span className="text-sm text-muted-foreground">{t('arrived')}</span>
              <Badge className="bg-green-500/10 text-green-500">{stats?.boxesByStatus.arrived || 0}</Badge>
            </div>
          </div>
        </Card>

        <Card className="p-4 bg-card border-border">
          <h3 className="text-sm font-medium text-foreground mb-3 flex items-center gap-2">
            <MapPin className="h-4 w-4" />
            {t('byLocation')}
          </h3>
          <div className="space-y-2">
            <div className="flex items-center justify-between">
              <span className="text-sm text-muted-foreground">🇨🇳 {t('china')}</span>
              <Badge className="bg-red-500/10 text-red-500">{stats?.boxesByLocation.china || 0}</Badge>
            </div>
            <div className="flex items-center justify-between">
              <span className="text-sm text-muted-foreground">🚚 {t('transit')}</span>
              <Badge className="bg-yellow-500/10 text-yellow-500">{stats?.boxesByLocation.transit || 0}</Badge>
            </div>
            <div className="flex items-center justify-between">
              <span className="text-sm text-muted-foreground">🇺🇿 {t('uzbekistan')}</span>
              <Badge className="bg-green-500/10 text-green-500">{stats?.boxesByLocation.uzbekistan || 0}</Badge>
            </div>
          </div>
        </Card>
      </div>

      {/* Filters and Search */}
      <Card className="p-4 sm:p-6 bg-card border-border">
        <div className="flex flex-col sm:flex-row gap-3 mb-6">
          <div className="relative flex-1">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
            <Input
              placeholder={t('searchByBoxOrLocation')}
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              className="pl-10 bg-input border-border min-h-[44px]"
            />
          </div>

          <Select value={eventTypeFilter} onValueChange={setEventTypeFilter}>
            <SelectTrigger className="w-full sm:w-[160px] min-h-[44px]">
              <SelectValue placeholder={t('eventType')} />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="all">{t('allEvents')}</SelectItem>
              <SelectItem value="created">{t('created')}</SelectItem>
              <SelectItem value="sealed">{t('eventSealed')}</SelectItem>
              <SelectItem value="in_transit">{t('departed')}</SelectItem>
              <SelectItem value="arrived">{t('arrived')}</SelectItem>
              <SelectItem value="verified">{t('verified')}</SelectItem>
            </SelectContent>
          </Select>

          <Select value={locationFilter} onValueChange={setLocationFilter}>
            <SelectTrigger className="w-full sm:w-[150px] min-h-[44px]">
              <SelectValue placeholder={t('location')} />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="all">{t('allLocations')}</SelectItem>
              <SelectItem value="china">🇨🇳 {t('china')}</SelectItem>
              <SelectItem value="transit">🚚 {t('transit')}</SelectItem>
              <SelectItem value="uzbekistan">🇺🇿 {t('uzbekistan')}</SelectItem>
            </SelectContent>
          </Select>

          <Select value={dateRange} onValueChange={setDateRange}>
            <SelectTrigger className="w-full sm:w-[130px] min-h-[44px]">
              <SelectValue placeholder={t('time')} />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="all">{t('allTime')}</SelectItem>
              <SelectItem value="today">{t('today')}</SelectItem>
              <SelectItem value="week">{t('thisWeek')}</SelectItem>
              <SelectItem value="month">{t('thisMonth')}</SelectItem>
            </SelectContent>
          </Select>
        </div>

        {/* Active Filters */}
        {(eventTypeFilter !== 'all' || locationFilter !== 'all' || dateRange !== 'all' || searchQuery) && (
          <div className="flex flex-wrap gap-2 mb-4">
            {searchQuery && (
              <Badge variant="secondary" className="gap-1">
                {t('search')}: {searchQuery}
                <button onClick={() => setSearchQuery('')} className="ml-1 hover:text-destructive">×</button>
              </Badge>
            )}
            {eventTypeFilter !== 'all' && (
              <Badge variant="secondary" className="gap-1">
                {t('type')}: {eventTypeFilter}
                <button onClick={() => setEventTypeFilter('all')} className="ml-1 hover:text-destructive">×</button>
              </Badge>
            )}
            {locationFilter !== 'all' && (
              <Badge variant="secondary" className="gap-1">
                {t('location')}: {locationFilter}
                <button onClick={() => setLocationFilter('all')} className="ml-1 hover:text-destructive">×</button>
              </Badge>
            )}
            {dateRange !== 'all' && (
              <Badge variant="secondary" className="gap-1">
                {t('time')}: {dateRange}
                <button onClick={() => setDateRange('all')} className="ml-1 hover:text-destructive">×</button>
              </Badge>
            )}
            <Button 
              variant="ghost" 
              size="sm" 
              onClick={() => {
                setSearchQuery('');
                setEventTypeFilter('all');
                setLocationFilter('all');
                setDateRange('all');
              }}
              className="text-xs h-6"
            >
              {t('clearAll')}
            </Button>
          </div>
        )}

        {/* Results count */}
        <div className="text-sm text-muted-foreground mb-4">
          {filteredEvents.length} {t('eventsFound')}
        </div>

        {isLoading ? (
          <LoadingSkeleton count={5} />
        ) : filteredEvents.length > 0 ? (
          <div className="relative">
            <div className="absolute left-4 sm:left-6 top-0 bottom-0 w-0.5 bg-border"></div>

            <div className="space-y-6">
              {filteredEvents.map((event) => {
                const Icon = getEventIcon(event.event_type);
                return (
                  <div key={event.id} className="relative pl-12 sm:pl-16">
                    <div className={`absolute left-0 w-8 h-8 sm:w-12 sm:h-12 rounded-lg sm:rounded-xl flex items-center justify-center ${getEventColor(event.event_type)}`}>
                      <Icon className="h-4 w-4 sm:h-6 sm:w-6" />
                    </div>

                    <Card className="p-3 sm:p-4 bg-muted border-border transition-all duration-200 hover:bg-muted/70 hover:shadow-sm">
                      <div className="flex flex-col sm:flex-row sm:justify-between sm:items-start gap-1 mb-2">
                        <h3 className="font-medium text-foreground capitalize">
                          {event.event_type.replace('_', ' ')}
                        </h3>
                        <span className="text-xs text-muted-foreground">
                          {new Date(event.created_at).toLocaleString('uz-UZ')}
                        </span>
                      </div>

                      {event.description && (
                        <p className="text-sm text-muted-foreground mb-2">
                          {event.description}
                        </p>
                      )}

                      <div className="flex flex-wrap items-center gap-3 mt-2">
                        {event.location && (
                          <div className="flex items-center gap-1 text-xs text-muted-foreground">
                            <MapPin className="h-3 w-3" />
                            <span>{event.location}</span>
                          </div>
                        )}
                        <div className="flex items-center gap-1">
                          <span className="text-xs text-muted-foreground">Quti:</span>
                          <span className="text-xs font-mono text-primary font-medium">
                            {(event as any).box_number || event.entity_id.slice(0, 8)}
                          </span>
                        </div>
                      </div>
                    </Card>
                  </div>
                );
              })}
            </div>
          </div>
        ) : trackingEvents && trackingEvents.length > 0 ? (
          <div className="text-center py-12">
            <Filter className="h-16 w-16 text-muted-foreground mx-auto mb-4 opacity-50" />
            <p className="text-muted-foreground mb-2">Filtr natijasi topilmadi</p>
            <Button 
              variant="outline" 
              size="sm"
              onClick={() => {
                setSearchQuery('');
                setEventTypeFilter('all');
                setLocationFilter('all');
                setDateRange('all');
              }}
            >
              Filtrlarni tozalash
            </Button>
          </div>
        ) : (
          <div className="text-center py-12">
            <Box className="h-16 w-16 text-muted-foreground mx-auto mb-4 opacity-50" />
            <p className="text-muted-foreground">Hozircha quti kuzatuv voqealari yo'q</p>
          </div>
        )}
      </Card>
    </div>
  );
}

import { useState } from 'react';
import { Card } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { Calendar as CalendarComponent } from '@/components/ui/calendar';
import { Popover, PopoverContent, PopoverTrigger } from '@/components/ui/popover';
import { useQuery } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';
import { LoadingSkeleton } from '@/components/ui/loading-skeleton';
import { 
  FileText, 
  Download, 
  Calendar, 
  CheckCircle, 
  AlertTriangle, 
  XCircle,
  Package,
  TrendingUp,
  Clock,
  User,
  ChevronDown,
  ChevronUp,
  ShieldAlert
} from 'lucide-react';
import { useTranslation } from 'react-i18next';
import { format, subDays, startOfDay, endOfDay } from 'date-fns';
import { useUserRole } from '@/hooks/useUserRole';
import { cn } from '@/lib/utils';

interface DailySummary {
  date: string;
  totalSessions: number;
  totalItems: number;
  okCount: number;
  defectiveCount: number;
  missingCount: number;
  defectRate: number;
  boxes: string[];
}

export default function VerificationReports() {
  const { t } = useTranslation();
  const { isChiefManager, isChinaManager, isChinaStaff, isLoading: roleLoading } = useUserRole();

  // Role-based access control - only China staff and Chief Manager
  const canAccess = isChiefManager || isChinaManager || isChinaStaff;

  const [startDate, setStartDate] = useState<Date>(subDays(new Date(), 7));
  const [endDate, setEndDate] = useState<Date>(new Date());
  const [expandedDate, setExpandedDate] = useState<string | null>(null);

  // Access denied check
  if (!roleLoading && !canAccess) {
    return (
      <div className="flex flex-col items-center justify-center min-h-[60vh] text-center">
        <ShieldAlert className="h-16 w-16 text-destructive mb-4" />
        <h2 className="text-xl font-semibold text-foreground mb-2">{t('vrpt_no_access')}</h2>
        <p className="text-muted-foreground">{t('vrpt_no_access_msg')}</p>
      </div>
    );
  }

  // Fetch verification sessions with details
  const { data: sessions, isLoading } = useQuery({
    queryKey: ['verification-reports', startDate.toISOString(), endDate.toISOString()],
    queryFn: async () => {
      const start = startOfDay(startDate);
      const end = endOfDay(endDate);

      // Note: `verification_sessions.verified_by` has no FK to `profiles`,
      // so we fetch profiles in a second query to avoid PostgREST embed errors.
      const { data: sessionsData, error: sessionsError } = await supabase
        .from('verification_sessions')
        .select(
          `id, box_id, status, ok_count, defective_count, missing_count, total_items, verified_count, completed_at, created_at, verified_by,
           boxes!verification_sessions_box_id_fkey(box_number, location)`
        )
        .gte('created_at', start.toISOString())
        .lte('created_at', end.toISOString())
        .order('created_at', { ascending: false });

      if (sessionsError) throw sessionsError;

      const verifierIds = Array.from(
        new Set((sessionsData ?? []).map((s) => s.verified_by).filter(Boolean))
      ) as string[];

      let verifierMap: Record<string, string> = {};
      if (verifierIds.length > 0) {
        const { data: profilesData, error: profilesError } = await supabase
          .from('profiles')
          .select('id, full_name')
          .in('id', verifierIds);

        if (profilesError) throw profilesError;

        verifierMap = (profilesData ?? []).reduce(
          (acc: Record<string, string>, p) => {
            if (p.id) acc[p.id] = p.full_name ?? '';
            return acc;
          },
          {}
        );
      }

      return (sessionsData ?? []).map((s) => ({
        ...s,
        verifier_full_name: s.verified_by ? verifierMap[s.verified_by] ?? null : null,
      }));
    },
    retry: 1,
    staleTime: 60000, // 1 minute cache
    gcTime: 300000, // 5 minute garbage collection
  });

  // Fetch defect categories breakdown
  const { data: defectBreakdown } = useQuery({
    queryKey: ['defect-breakdown', startDate.toISOString(), endDate.toISOString()],
    queryFn: async () => {
      const start = startOfDay(startDate);
      const end = endOfDay(endDate);

      const { data, error } = await supabase
        .from('verification_items')
        .select('defect_type, status')
        .eq('status', 'defective')
        .gte('created_at', start.toISOString())
        .lte('created_at', end.toISOString());

      if (error) throw error;

      // Group by defect type
      const breakdown: Record<string, number> = {};
      data?.forEach(item => {
        const type = item.defect_type || 'Noma\'lum';
        breakdown[type] = (breakdown[type] || 0) + 1;
      });

      return breakdown;
    },
    staleTime: 60000, // 1 minute cache
    gcTime: 300000, // 5 minute garbage collection
  });

  // Calculate daily summaries
  const dailySummaries: DailySummary[] = sessions ? 
    Object.entries(
      sessions.reduce((acc: Record<string, any>, session) => {
        const date = format(new Date(session.created_at || ''), 'yyyy-MM-dd');
        if (!acc[date]) {
          acc[date] = {
            date,
            totalSessions: 0,
            totalItems: 0,
            okCount: 0,
            defectiveCount: 0,
            missingCount: 0,
            boxes: [],
          };
        }
        acc[date].totalSessions++;
        acc[date].totalItems += session.total_items || 0;
        acc[date].okCount += session.ok_count || 0;
        acc[date].defectiveCount += session.defective_count || 0;
        acc[date].missingCount += session.missing_count || 0;
        if ((session as any).boxes?.box_number) {
          acc[date].boxes.push((session as any).boxes.box_number);
        }
        return acc;
      }, {})
    ).map(([_, summary]) => ({
      ...summary,
      defectRate: summary.totalItems > 0 
        ? ((summary.defectiveCount + summary.missingCount) / summary.totalItems * 100).toFixed(1)
        : 0,
    })).sort((a, b) => b.date.localeCompare(a.date)) : [];

  // Calculate totals
  const totals = dailySummaries.reduce(
    (acc, day) => ({
      sessions: acc.sessions + day.totalSessions,
      items: acc.items + day.totalItems,
      ok: acc.ok + day.okCount,
      defective: acc.defective + day.defectiveCount,
      missing: acc.missing + day.missingCount,
    }),
    { sessions: 0, items: 0, ok: 0, defective: 0, missing: 0 }
  );

  const overallDefectRate = totals.items > 0 
    ? ((totals.defective + totals.missing) / totals.items * 100).toFixed(1) 
    : '0';

  // Export to CSV
  const exportToCSV = () => {
    const headers = ['Sana', 'Sessiyalar', 'Jami mahsulotlar', 'OK', 'Nuqsonli', 'Yo\'q', 'Nuqson %', 'Qutilar'];
    const rows = dailySummaries.map(day => [
      day.date,
      day.totalSessions,
      day.totalItems,
      day.okCount,
      day.defectiveCount,
      day.missingCount,
      day.defectRate,
      day.boxes.join('; '),
    ]);

    const csvContent = [
      headers.join(','),
      ...rows.map(row => row.join(',')),
    ].join('\n');

    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement('a');
    link.href = URL.createObjectURL(blob);
    link.download = `verification-report-${format(new Date(), 'yyyy-MM-dd')}.csv`;
    link.click();
  };

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div>
          <h1 className="text-2xl sm:text-3xl font-bold text-foreground mb-2">
            {t('vrpt_title')}
          </h1>
          <p className="text-muted-foreground text-sm sm:text-base">
            {t('vrpt_subtitle')}
          </p>
        </div>
        <Button 
          onClick={exportToCSV}
          className="gap-2 bg-primary hover:bg-primary/90 min-h-[44px]"
        >
          <Download className="h-4 w-4" />
          {t('vrpt_export_csv')}
        </Button>
      </div>

      {/* Date Range Filter */}
      <Card className="p-4 bg-card border-border">
        <div className="flex flex-col sm:flex-row gap-4 items-start sm:items-center">
          <div className="flex items-center gap-2">
            <Calendar className="h-4 w-4 text-muted-foreground" />
            <span className="text-sm text-muted-foreground">{t('vrpt_period')}</span>
          </div>

          {/* Start Date Picker */}
          <Popover>
            <PopoverTrigger asChild>
              <Button
                variant="outline"
                className={cn(
                  "w-[160px] justify-start text-left font-normal min-h-[44px]",
                  !startDate && "text-muted-foreground"
                )}
              >
                <Calendar className="mr-2 h-4 w-4" />
                {startDate ? format(startDate, "dd.MM.yyyy") : <span>{t('vrpt_start')}</span>}
              </Button>
            </PopoverTrigger>
            <PopoverContent className="w-auto p-0" align="start">
              <CalendarComponent
                mode="single"
                selected={startDate}
                onSelect={(date) => date && setStartDate(date)}
                initialFocus
                className={cn("p-3 pointer-events-auto")}
              />
            </PopoverContent>
          </Popover>

          <span className="text-muted-foreground">—</span>

          {/* End Date Picker */}
          <Popover>
            <PopoverTrigger asChild>
              <Button
                variant="outline"
                className={cn(
                  "w-[160px] justify-start text-left font-normal min-h-[44px]",
                  !endDate && "text-muted-foreground"
                )}
              >
                <Calendar className="mr-2 h-4 w-4" />
                {endDate ? format(endDate, "dd.MM.yyyy") : <span>{t('vrpt_end')}</span>}
              </Button>
            </PopoverTrigger>
            <PopoverContent className="w-auto p-0" align="start">
              <CalendarComponent
                mode="single"
                selected={endDate}
                onSelect={(date) => date && setEndDate(date)}
                initialFocus
                className={cn("p-3 pointer-events-auto")}
              />
            </PopoverContent>
          </Popover>
        </div>
      </Card>

      {/* Summary Stats */}
      <div className="grid grid-cols-2 md:grid-cols-5 gap-4">
        <Card className="p-4 bg-card border-border cursor-pointer hover:shadow-lg hover:border-primary/50 transition-all">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 rounded-lg bg-primary/10 flex items-center justify-center">
              <FileText className="h-5 w-5 text-primary" />
            </div>
            <div>
              <p className="text-xs text-muted-foreground">{t('vrpt_sessions')}</p>
              <p className="text-xl font-bold text-foreground">{totals.sessions}</p>
            </div>
          </div>
        </Card>

        <Card className="p-4 bg-card border-border cursor-pointer hover:shadow-lg hover:border-blue-500/50 transition-all">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 rounded-lg bg-blue-500/10 flex items-center justify-center">
              <Package className="h-5 w-5 text-blue-500" />
            </div>
            <div>
               <p className="text-xs text-muted-foreground">{t('vrpt_total_products')}</p>
              <p className="text-xl font-bold text-foreground">{totals.items}</p>
            </div>
          </div>
        </Card>

        <Card className="p-4 bg-card border-border cursor-pointer hover:shadow-lg hover:border-green-500/50 transition-all">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 rounded-lg bg-green-500/10 flex items-center justify-center">
              <CheckCircle className="h-5 w-5 text-green-500" />
            </div>
            <div>
              <p className="text-xs text-muted-foreground">OK</p>
              <p className="text-xl font-bold text-green-500">{totals.ok}</p>
            </div>
          </div>
        </Card>

        <Card className="p-4 bg-card border-border cursor-pointer hover:shadow-lg hover:border-yellow-500/50 transition-all">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 rounded-lg bg-yellow-500/10 flex items-center justify-center">
              <AlertTriangle className="h-5 w-5 text-yellow-500" />
            </div>
            <div>
               <p className="text-xs text-muted-foreground">{t('vrpt_defective')}</p>
              <p className="text-xl font-bold text-yellow-500">{totals.defective}</p>
            </div>
          </div>
        </Card>

        <Card className="p-4 bg-card border-border cursor-pointer hover:shadow-lg hover:border-red-500/50 transition-all">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 rounded-lg bg-red-500/10 flex items-center justify-center">
              <TrendingUp className="h-5 w-5 text-red-500" />
            </div>
            <div>
              <p className="text-xs text-muted-foreground">{t('vrpt_defect_percent')}</p>
              <p className="text-xl font-bold text-red-500">{overallDefectRate}%</p>
            </div>
          </div>
        </Card>
      </div>

      {/* Defect Breakdown */}
      {defectBreakdown && Object.keys(defectBreakdown).length > 0 && (
        <Card className="p-4 sm:p-6 bg-card border-border">
          <h3 className="font-semibold text-foreground mb-4">{t('vrpt_defect_types')}</h3>
          <div className="flex flex-wrap gap-3">
            {Object.entries(defectBreakdown).map(([type, count]) => (
              <Badge 
                key={type} 
                variant="outline" 
                className="px-3 py-1.5 text-sm border-yellow-500/50 text-yellow-500"
              >
                {type}: {count}
              </Badge>
            ))}
          </div>
        </Card>
      )}

      {/* Daily Breakdown */}
      <Card className="p-4 sm:p-6 bg-card border-border">
        <h3 className="font-semibold text-foreground mb-4">{t('vrpt_daily_report')}</h3>

        {isLoading ? (
          <LoadingSkeleton count={5} compact />
        ) : dailySummaries.length > 0 ? (
          <div className="space-y-3">
            {dailySummaries.map((day) => (
              <div key={day.date} className="border border-border rounded-lg overflow-hidden">
                <button
                  className="w-full p-4 flex items-center justify-between hover:bg-muted/50 transition-colors"
                  onClick={() => setExpandedDate(expandedDate === day.date ? null : day.date)}
                >
                  <div className="flex items-center gap-4">
                    <div className="text-left">
                      <p className="font-medium text-foreground">
                        {format(new Date(day.date), 'dd MMM yyyy')}
                      </p>
                      <p className="text-xs text-muted-foreground">
                        {day.totalSessions} {t('vrpt_sessions').toLowerCase()}
                      </p>
                    </div>
                  </div>

                  <div className="flex items-center gap-4">
                    <div className="hidden sm:flex items-center gap-3">
                      <Badge variant="outline" className="border-green-500/50 text-green-500">
                        <CheckCircle className="h-3 w-3 mr-1" />
                        {day.okCount}
                      </Badge>
                      <Badge variant="outline" className="border-yellow-500/50 text-yellow-500">
                        <AlertTriangle className="h-3 w-3 mr-1" />
                        {day.defectiveCount}
                      </Badge>
                      <Badge variant="outline" className="border-red-500/50 text-red-500">
                        <XCircle className="h-3 w-3 mr-1" />
                        {day.missingCount}
                      </Badge>
                    </div>
                    <div className="text-right">
                      <p className={`text-sm font-medium ${
                        Number(day.defectRate) > 5 ? 'text-red-500' : 
                        Number(day.defectRate) > 2 ? 'text-yellow-500' : 'text-green-500'
                      }`}>
                        {day.defectRate}%
                      </p>
                    </div>
                    {expandedDate === day.date ? (
                      <ChevronUp className="h-4 w-4 text-muted-foreground" />
                    ) : (
                      <ChevronDown className="h-4 w-4 text-muted-foreground" />
                    )}
                  </div>
                </button>

                {expandedDate === day.date && (
                  <div className="p-4 border-t border-border bg-muted/30">
                    <div className="grid grid-cols-2 sm:grid-cols-4 gap-4 mb-4">
                      <div>
                        <p className="text-xs text-muted-foreground">{t('vrpt_total_items')}</p>
                        <p className="text-lg font-semibold text-foreground">{day.totalItems}</p>
                      </div>
                      <div>
                        <p className="text-xs text-muted-foreground">OK</p>
                        <p className="text-lg font-semibold text-green-500">{day.okCount}</p>
                      </div>
                      <div>
                        <p className="text-xs text-muted-foreground">{t('vrpt_defective')}</p>
                        <p className="text-lg font-semibold text-yellow-500">{day.defectiveCount}</p>
                      </div>
                      <div>
                        <p className="text-xs text-muted-foreground">{t('vrpt_missing')}</p>
                        <p className="text-lg font-semibold text-red-500">{day.missingCount}</p>
                      </div>
                    </div>
                    {day.boxes.length > 0 && (
                      <div>
                        <p className="text-xs text-muted-foreground mb-2">{t('vrpt_checked_boxes')}</p>
                        <div className="flex flex-wrap gap-2">
                          {day.boxes.map((boxNum, idx) => (
                            <Badge key={idx} variant="secondary" className="text-xs">
                              <Package className="h-3 w-3 mr-1" />
                              {boxNum}
                            </Badge>
                          ))}
                        </div>
                      </div>
                    )}
                  </div>
                )}
              </div>
            ))}
          </div>
        ) : (
          <div className="text-center py-12">
            <FileText className="h-16 w-16 text-muted-foreground mx-auto mb-4 opacity-50" />
            <p className="text-muted-foreground">{t('vrpt_no_sessions')}</p>
          </div>
        )}
      </Card>

      {/* Recent Sessions Detail */}
      <Card className="p-4 sm:p-6 bg-card border-border">
        <h3 className="font-semibold text-foreground mb-4">{t('vrpt_recent_sessions')}</h3>

        {isLoading ? (
          <LoadingSkeleton count={3} compact />
        ) : sessions && sessions.length > 0 ? (
          <div className="space-y-3">
            {sessions.slice(0, 10).map((session) => (
              <div 
                key={session.id} 
                className="p-4 border border-border rounded-lg hover:bg-muted/30 transition-colors"
              >
                <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-3">
                  <div className="flex items-center gap-3">
                    <div className="w-10 h-10 rounded-lg bg-primary/10 flex items-center justify-center">
                      <Package className="h-5 w-5 text-primary" />
                    </div>
                    <div>
                      <p className="font-medium text-foreground">
                        {(session as any).boxes?.box_number || t('vrpt_unknown_box')}
                      </p>
                      <div className="flex items-center gap-2 text-xs text-muted-foreground">
                        <Clock className="h-3 w-3" />
                        {format(new Date(session.created_at || ''), 'dd MMM yyyy HH:mm')}
                        {(session as any).verifier_full_name && (
                          <>
                            <span>•</span>
                            <User className="h-3 w-3" />
                            {(session as any).verifier_full_name}
                          </>
                        )}
                      </div>
                    </div>
                  </div>

                  <div className="flex items-center gap-2">
                    <Badge 
                      variant={session.status === 'completed' ? 'default' : 'secondary'}
                      className={session.status === 'completed' ? 'bg-green-500' : ''}
                    >
                      {session.status === 'completed' ? t('vrpt_completed') : t('vrpt_in_progress')}
                    </Badge>
                    <div className="flex items-center gap-1.5 text-sm">
                      <span className="text-green-500">{session.ok_count || 0}</span>
                      <span className="text-muted-foreground">/</span>
                      <span className="text-yellow-500">{session.defective_count || 0}</span>
                      <span className="text-muted-foreground">/</span>
                      <span className="text-red-500">{session.missing_count || 0}</span>
                    </div>
                  </div>
                </div>
              </div>
            ))}
          </div>
        ) : (
          <div className="text-center py-8">
            <p className="text-muted-foreground">{t('vrpt_no_sessions_yet')}</p>
          </div>
        )}
      </Card>
    </div>
  );
}

import { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { useCart } from '@/hooks/useCart';
import { formatPrice } from '@/hooks/useStoreProducts';
import { useDocumentMeta } from '@/hooks/useDocumentMeta';
import { supabase } from '@/integrations/supabase/client';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Textarea } from '@/components/ui/textarea';
import { RadioGroup, RadioGroupItem } from '@/components/ui/radio-group';
import { Dialog, DialogContent, DialogHeader, DialogTitle } from '@/components/ui/dialog';
import { ArrowLeft, Loader2, Tag, CheckCircle, XCircle, CreditCard, Copy, Check } from 'lucide-react';
import { useQuery } from '@tanstack/react-query';
import { toast } from 'sonner';
import { STORE } from '@/lib/storeConfig';
import { useTranslation } from 'react-i18next';

export default function StoreCheckout() {
  const { t } = useTranslation();
  const navigate = useNavigate();
  const { items, total, clear, isEmpty } = useCart();
  const [loading, setLoading] = useState(false);
  const [showPaymentDialog, setShowPaymentDialog] = useState(false);

  useDocumentMeta({ title: t('sf_checkout'), description: 'AliBrand.uz — ' + t('sf_checkout') });

  const [form, setForm] = useState({
    name: '', phone: '+998', address: '',
    delivery: 'delivery' as 'delivery' | 'pickup',
    payment: 'card' as 'card',
    notes: '',
  });

  // Promo code state
  const [promoInput, setPromoInput] = useState('');
  const [promoApplied, setPromoApplied] = useState<{ code: string; discount_type: string; discount_value: number } | null>(null);
  const [promoLoading, setPromoLoading] = useState(false);
  const [promoError, setPromoError] = useState('');
  const [cardCopied, setCardCopied] = useState(false);
  const [customerCard, setCustomerCard] = useState('');

  // Fetch active payment card
  const { data: activeCard } = useQuery({
    queryKey: ['payment-card-checkout'],
    queryFn: async () => {
      const { data } = await supabase
        .from('payment_cards')
        .select('card_number, card_holder, bank_name')
        .eq('is_active', true)
        .maybeSingle();
      return data;
    },
  });

  const copyCardNumber = () => {
    if (activeCard) {
      navigator.clipboard.writeText(activeCard.card_number.replace(/\s/g, ''));
      setCardCopied(true);
      setTimeout(() => setCardCopied(false), 2000);
    }
  };

  if (isEmpty) {
    return (
      <div className="px-4 py-20 text-center">
        <p className="text-muted-foreground mb-4">{t('sf_cart_empty')}</p>
        <Link to="/catalog"><Button className="gradient-gold-purple text-white font-bold border-0">{t('sf_back_to_catalog')}</Button></Link>
      </div>
    );
  }

  const deliveryFee = form.delivery === 'delivery' ? STORE.deliveryFee : 0;

  // Calculate discount
  let discountAmount = 0;
  if (promoApplied) {
    if (promoApplied.discount_type === 'percent') {
      discountAmount = Math.round(total * promoApplied.discount_value / 100);
    } else {
      discountAmount = Math.min(promoApplied.discount_value, total);
    }
  }

  const grandTotal = total - discountAmount + deliveryFee;

  const handleApplyPromo = async () => {
    const code = promoInput.trim().toUpperCase();
    if (!code) return;
    setPromoLoading(true);
    setPromoError('');
    try {
      const { data, error } = await supabase
        .from('promo_codes')
        .select('*')
        .eq('code', code)
        .eq('is_active', true)
        .maybeSingle();

      if (error) throw error;
      if (!data) { setPromoError('Promo kod topilmadi'); setPromoLoading(false); return; }
      if (data.max_uses && data.used_count >= data.max_uses) { setPromoError('Promo kod tugagan'); setPromoLoading(false); return; }
      if (data.min_order_amount && total < data.min_order_amount) {
        setPromoError(`Minimal buyurtma: ${formatPrice(data.min_order_amount)}`);
        setPromoLoading(false);
        return;
      }

      setPromoApplied({ code: data.code, discount_type: data.discount_type, discount_value: Number(data.discount_value) });
      toast.success('Promo kod qo\'llandi!');
    } catch {
      setPromoError('Xatolik yuz berdi');
    } finally {
      setPromoLoading(false);
    }
  };

  const handleRemovePromo = () => {
    setPromoApplied(null);
    setPromoInput('');
    setPromoError('');
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!form.name.trim() || form.phone.length < 13) { toast.error(t('sf_fill_name_phone')); return; }
    if (form.delivery === 'delivery' && !form.address.trim()) { toast.error(t('sf_enter_address')); return; }
    setShowPaymentDialog(true);
  };

  const confirmOrder = async () => {
    setLoading(true);
    try {
      const productIds = items.map(i => i.productId);
      const { data: stockData } = await supabase.from('products').select('id, name, tashkent_manual_stock').in('id', productIds);
      const outOfStock = items.filter(item => { const prod = stockData?.find(p => p.id === item.productId); return !prod || (prod.tashkent_manual_stock || 0) < item.quantity; });
      if (outOfStock.length > 0) { toast.error(`"${outOfStock[0].name}" ${t('sf_not_enough_stock')}`); setLoading(false); setShowPaymentDialog(false); return; }

      const orderItems = items.map(item => ({ product_id: item.productId, variant_id: item.variantId || null, name: item.name, variant_name: item.variantName || null, quantity: item.quantity, price: item.price, image: item.image || null }));

      const { data, error } = await supabase.from('store_orders').insert({
        customer_name: form.name.trim(), customer_phone: form.phone.trim(),
        customer_address: form.delivery === 'delivery' ? form.address.trim() : null,
        delivery_type: form.delivery, payment_type: form.payment,
        items: orderItems, subtotal: total, delivery_fee: deliveryFee, total_amount: grandTotal,
        notes: form.notes.trim() || null,
        promo_code: promoApplied?.code || null,
        discount_amount: discountAmount || 0,
        paynet_status: null,
        status: 'pending_payment',
        customer_card_number: customerCard.trim() || null,
      } as any).select('id, order_number').single();

      if (error) throw error;

      if (promoApplied) {
        const { data: pc } = await supabase.from('promo_codes').select('id, used_count').eq('code', promoApplied.code).maybeSingle();
        if (pc) {
          await supabase.from('promo_codes').update({ used_count: (pc.used_count || 0) + 1 } as any).eq('id', pc.id);
        }
      }

      supabase.functions.invoke('send-telegram-alert', {
        body: { event_type: 'new_store_order', data: { order_number: data.order_number || data.id.slice(0, 8), customer_name: form.name.trim(), customer_phone: form.phone.trim(), total: grandTotal, items_count: items.length, delivery_type: form.delivery, payment_type: form.payment, address: form.delivery === 'delivery' ? form.address.trim() : null }, target_roles: ['rahbar', 'bosh_admin', 'uz_manager'] }
      }).catch(console.error);

      sessionStorage.setItem(`order_${data.id}`, JSON.stringify({ order_number: data.order_number, items: items.map(i => ({ name: i.name, quantity: i.quantity, price: i.price })), delivery_fee: deliveryFee, discount_amount: discountAmount, promo_code: promoApplied?.code, total_amount: grandTotal, payment_type: form.payment }));

      clear();
      navigate(`/order-success/${data.id}`);
    } catch (err) { console.error('Order error:', err); toast.error(t('sf_order_error')); } finally { setLoading(false); }
  };


  return (
    <div className="px-4 py-4 max-w-2xl mx-auto">
      <Link to="/cart" className="inline-flex items-center gap-1 text-sm text-muted-foreground hover:text-primary mb-4 transition-colors">
        <ArrowLeft className="w-4 h-4" /> {t('sf_back_to_cart')}
      </Link>
      <h1 className="text-2xl font-extrabold mb-6">{t('sf_checkout')}</h1>
      <form onSubmit={handleSubmit} noValidate className="space-y-6">
        <div className="bg-card rounded-xl border border-border/50 p-4 space-y-4">
          <h2 className="font-semibold">{t('sf_contact_info')}</h2>
          <div><Label htmlFor="name">{t('sf_your_name')} *</Label><Input id="name" value={form.name} onChange={e => setForm(f => ({ ...f, name: e.target.value }))} placeholder={t('sf_enter_name')} className="bg-muted/30 border-border/50" /></div>
          <div><Label htmlFor="phone">{t('sf_phone')} *</Label><Input id="phone" value={form.phone} onChange={e => setForm(f => ({ ...f, phone: e.target.value }))} placeholder="+998 90 123 45 67" className="bg-muted/30 border-border/50" /></div>
        </div>
        <div className="bg-card rounded-xl border border-border/50 p-4 space-y-4">
          <h2 className="font-semibold">{t('sf_delivery')}</h2>
          <RadioGroup value={form.delivery} onValueChange={(v) => setForm(f => ({ ...f, delivery: v as any }))}>
            <div className="flex items-center gap-3 p-3 rounded-lg border border-border/50 hover:border-primary/30 transition-colors">
              <RadioGroupItem value="delivery" id="delivery" />
              <Label htmlFor="delivery" className="flex-1 cursor-pointer"><span className="font-medium">{t('sf_delivery_option')}</span><span className="text-sm text-muted-foreground ml-2">{formatPrice(STORE.deliveryFee)}</span></Label>
            </div>
            <div className="flex items-center gap-3 p-3 rounded-lg border border-border/50 hover:border-primary/30 transition-colors">
              <RadioGroupItem value="pickup" id="pickup" />
              <Label htmlFor="pickup" className="flex-1 cursor-pointer"><span className="font-medium">{t('sf_pickup')}</span><span className="text-sm text-muted-foreground ml-2">{t('sf_free')}</span></Label>
            </div>
          </RadioGroup>
          {form.delivery === 'delivery' && (
            <div><Label htmlFor="address">{t('sf_address')} *</Label><Input id="address" value={form.address} onChange={e => setForm(f => ({ ...f, address: e.target.value }))} placeholder={t('sf_address_placeholder')} className="bg-muted/30 border-border/50" /></div>
          )}
        </div>
        <div className="bg-card rounded-xl border border-border/50 p-4 space-y-4">
          <h2 className="font-semibold">{t('sf_payment_method')}</h2>
          <div className="flex items-center gap-3 p-3 rounded-lg border border-primary/30 bg-primary/5">
            <CreditCard className="w-4 h-4 text-primary" />
            <span className="font-medium">Karta orqali (oldindan to'lov)</span>
          </div>
        </div>

        {/* Promo Code */}
        <div className="bg-card rounded-xl border border-border/50 p-4 space-y-3">
          <h2 className="font-semibold flex items-center gap-2"><Tag className="w-4 h-4" /> Promo kod</h2>
          {promoApplied ? (
            <div className="flex items-center justify-between bg-primary/10 rounded-lg p-3">
              <div className="flex items-center gap-2">
                <CheckCircle className="w-4 h-4 text-primary" />
                <span className="font-mono font-bold">{promoApplied.code}</span>
                <span className="text-sm text-muted-foreground">
                  ({promoApplied.discount_type === 'percent' ? `${promoApplied.discount_value}%` : formatPrice(promoApplied.discount_value)})
                </span>
              </div>
              <Button type="button" variant="ghost" size="sm" onClick={handleRemovePromo}>
                <XCircle className="w-4 h-4" />
              </Button>
            </div>
          ) : (
            <div className="flex gap-2">
              <Input
                value={promoInput}
                onChange={e => { setPromoInput(e.target.value); setPromoError(''); }}
                placeholder="Promo kodni kiriting"
                className="bg-muted/30 border-border/50 uppercase"
              />
              <Button type="button" variant="outline" onClick={handleApplyPromo} disabled={promoLoading || !promoInput.trim()}>
                {promoLoading ? <Loader2 className="w-4 h-4 animate-spin" /> : 'Qo\'llash'}
              </Button>
            </div>
          )}
          {promoError && <p className="text-sm text-destructive">{promoError}</p>}
        </div>

        <div className="bg-card rounded-xl border border-border/50 p-4 space-y-3">
          <Label htmlFor="notes">{t('sf_notes')}</Label>
          <Textarea id="notes" value={form.notes} onChange={e => setForm(f => ({ ...f, notes: e.target.value }))} placeholder={t('sf_notes_placeholder')} rows={2} className="bg-muted/30 border-border/50" />
        </div>
        <div className="bg-card rounded-xl border border-primary/20 p-4 space-y-2 glow-gold-sm">
          <h2 className="font-semibold mb-3">{t('sf_order_summary')}</h2>
          {items.map(item => (<div key={item.variantId || item.productId} className="flex justify-between text-sm"><span className="text-muted-foreground">{item.quantity}x {item.name}</span><span>{formatPrice(item.price * item.quantity)}</span></div>))}
          {discountAmount > 0 && (
            <div className="flex justify-between text-sm text-primary"><span>Chegirma ({promoApplied?.code})</span><span>-{formatPrice(discountAmount)}</span></div>
          )}
          {deliveryFee > 0 && (<div className="flex justify-between text-sm"><span className="text-muted-foreground">{t('sf_delivery')}</span><span>{formatPrice(deliveryFee)}</span></div>)}
          <div className="flex justify-between text-lg font-bold pt-2 border-t border-border/50"><span>{t('sf_total')}</span><span className="text-primary">{formatPrice(grandTotal)}</span></div>
        </div>
        <Button type="submit" size="lg" className="w-full text-base gradient-gold-purple text-white font-bold border-0 hover:opacity-90 glow-gold-sm" disabled={loading}>
          {t('sf_confirm_order')}
        </Button>
      </form>

      <Dialog open={showPaymentDialog} onOpenChange={setShowPaymentDialog}>
        <DialogContent className="sm:max-w-md">
          <DialogHeader>
            <DialogTitle className="flex items-center gap-2">
              <CreditCard className="w-5 h-5 text-primary" />
              To'lov
            </DialogTitle>
          </DialogHeader>
          <div className="space-y-4">
            {activeCard ? (
              <div className="p-4 bg-primary/5 rounded-lg border border-primary/20 space-y-3">
                <p className="text-sm font-medium text-muted-foreground">Quyidagi kartaga pul o'tkazing:</p>
                <div className="flex items-center justify-between">
                  <p className="font-mono font-bold text-xl tracking-wider">{activeCard.card_number}</p>
                  <Button type="button" variant="ghost" size="sm" onClick={copyCardNumber} className="gap-1">
                    {cardCopied ? <><Check className="w-4 h-4 text-primary" /> Nusxalandi</> : <><Copy className="w-4 h-4" /> Nusxalash</>}
                  </Button>
                </div>
                <p className="text-sm text-muted-foreground">{activeCard.card_holder} ({activeCard.bank_name})</p>
              </div>
            ) : (
              <p className="text-sm text-muted-foreground">Karta ma'lumotlari yuklanmadi</p>
            )}
            <div className="flex justify-between items-center p-3 bg-muted/30 rounded-lg border border-border/50">
              <span className="font-medium">Jami to'lov:</span>
              <span className="text-xl font-bold text-primary">{formatPrice(grandTotal)}</span>
            </div>
            <div className="space-y-2">
              <Label htmlFor="customerCard">Sizning karta raqamingiz *</Label>
              <Input
                id="customerCard"
                value={customerCard}
                onChange={e => setCustomerCard(e.target.value.replace(/[^\d\s]/g, '').slice(0, 19))}
                placeholder="8600 0000 0000 0000"
                className="bg-muted/30 border-border/50 font-mono tracking-wider"
                inputMode="numeric"
              />
              <p className="text-xs text-muted-foreground">Pul o'tkazgan kartangiz raqamini kiriting</p>
            </div>
            <Button
              onClick={confirmOrder}
              size="lg"
              className="w-full text-base gradient-gold-purple text-white font-bold border-0 hover:opacity-90 glow-gold-sm"
              disabled={loading || customerCard.replace(/\s/g, '').length < 16}
            >
              {loading && <Loader2 className="w-4 h-4 mr-2 animate-spin" />}
              To'lovni amalga oshirdim ✓
            </Button>
          </div>
        </DialogContent>
      </Dialog>
    </div>
  );
}

import { useParams, Link, useSearchParams } from 'react-router-dom';
import { formatPrice } from '@/hooks/useStoreProducts';
import { Button } from '@/components/ui/button';
import { CheckCircle, Phone, Search, Copy, Check } from 'lucide-react';
import { useEffect, useState } from 'react';
import { useQuery } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';
import { useTranslation } from 'react-i18next';

interface OrderData { order_number: string; items: any[]; delivery_fee: number; discount_amount?: number; promo_code?: string; total_amount: number; payment_type?: string; }

export default function StoreOrderSuccess() {
  const { t } = useTranslation();
  const { orderId } = useParams();
  const [searchParams] = useSearchParams();
  const [order, setOrder] = useState<OrderData | null>(null);
  const [cardCopied, setCardCopied] = useState(false);

  const { data: activeCard } = useQuery({
    queryKey: ['payment-card-success'],
    queryFn: async () => {
      const { data } = await supabase
        .from('payment_cards')
        .select('card_number, card_holder, bank_name')
        .eq('is_active', true)
        .maybeSingle();
      return data;
    },
  });

  const copyCardNumber = () => {
    if (activeCard) {
      navigator.clipboard.writeText(activeCard.card_number.replace(/\s/g, ''));
      setCardCopied(true);
      setTimeout(() => setCardCopied(false), 2000);
    }
  };

  useEffect(() => {
    const stored = sessionStorage.getItem(`order_${orderId}`);
    if (stored) { try { setOrder(JSON.parse(stored)); } catch {} }
  }, [orderId]);

  if (!order) {
    return (
      <div className="px-4 py-20 text-center">
        <CheckCircle className="w-20 h-20 mx-auto text-primary mb-4" />
        <h1 className="text-2xl font-extrabold mb-2">{t('sf_order_accepted')}</h1>
        <p className="text-muted-foreground mb-6">{t('sf_operator_will_call')}</p>
        <Link to="/"><Button variant="outline">{t('sf_back_to_home')}</Button></Link>
      </div>
    );
  }

  return (
    <div className="px-4 py-10 max-w-lg mx-auto text-center">
      <CheckCircle className="w-20 h-20 mx-auto text-primary mb-4" />
      <h1 className="text-2xl font-extrabold mb-2">To'lov tekshirilmoqda</h1>
      <p className="text-muted-foreground mb-2">{t('sf_order_number')}: <span className="font-mono font-bold text-primary">{order.order_number}</span></p>



      <div className="bg-card rounded-xl border border-border/50 p-4 text-left space-y-2 mb-6">
        {(order.items || []).map((item: any, i: number) => (
          <div key={i} className="flex justify-between text-sm"><span>{item.quantity}x {item.name}</span><span>{formatPrice(item.price * item.quantity)}</span></div>
        ))}
        {order.discount_amount && order.discount_amount > 0 && (
          <div className="flex justify-between text-sm text-primary"><span>Chegirma {order.promo_code ? `(${order.promo_code})` : ''}</span><span>-{formatPrice(order.discount_amount)}</span></div>
        )}
        {order.delivery_fee > 0 && (<div className="flex justify-between text-sm"><span className="text-muted-foreground">{t('sf_delivery')}</span><span>{formatPrice(order.delivery_fee)}</span></div>)}
        <div className="flex justify-between font-bold pt-2 border-t border-border/50"><span>{t('sf_total')}</span><span className="text-primary">{formatPrice(order.total_amount)}</span></div>
      </div>

      {order.payment_type === 'card' && activeCard && (
        <div className="bg-card rounded-xl border border-primary/20 p-4 mb-4 space-y-2">
          <p className="text-sm font-medium text-center text-muted-foreground">Quyidagi kartaga pul o'tkazing:</p>
          <div className="flex items-center justify-center gap-3">
            <p className="font-mono font-bold text-lg tracking-wider">{activeCard.card_number}</p>
            <Button variant="ghost" size="sm" onClick={copyCardNumber} className="gap-1">
              {cardCopied ? <Check className="w-4 h-4 text-primary" /> : <Copy className="w-4 h-4" />}
            </Button>
          </div>
          <p className="text-sm text-muted-foreground text-center">{activeCard.card_holder} ({activeCard.bank_name})</p>
        </div>
      )}

      <div className="bg-card rounded-xl border border-primary/20 p-4 mb-6 glow-gold-sm">
        <div className="flex items-center justify-center gap-2 text-primary font-medium"><Phone className="w-4 h-4" />To'lov tekshirilgach operator aloqaga chiqadi</div>
      </div>

      <div className="flex gap-3 justify-center">
        <Link to="/"><Button variant="outline" className="gap-2">{t('sf_back_to_home')}</Button></Link>
        <Link to="/track"><Button variant="outline" className="gap-2"><Search className="w-4 h-4" />{t('sf_track_order')}</Button></Link>
      </div>
    </div>
  );
}
